INSERT INTO `article_storage` VALUES (3, 2207, '宁王飘了，日赚2.3亿，回应比亚迪“闪充”：跟我学的，构不成挑战', '\"{\\\"title\\\": \\\"\\\\u5b81\\\\u738b\\\\u98d8\\\\u4e86\\\\uff0c\\\\u65e5\\\\u8d5a2.3\\\\u4ebf\\\\uff0c\\\\u56de\\\\u5e94\\\\u6bd4\\\\u4e9a\\\\u8fea\\\\u201c\\\\u95ea\\\\u5145\\\\u201d\\\\uff1a\\\\u8ddf\\\\u6211\\\\u5b66\\\\u7684\\\\uff0c\\\\u6784\\\\u4e0d\\\\u6210\\\\u6311\\\\u6218\\\", \\\"title_detail\\\": {\\\"type\\\": \\\"text/plain\\\", \\\"language\\\": null, \\\"base\\\": \\\"https://36kr.com/feed-article\\\", \\\"value\\\": \\\"\\\\u5b81\\\\u738b\\\\u98d8\\\\u4e86\\\\uff0c\\\\u65e5\\\\u8d5a2.3\\\\u4ebf\\\\uff0c\\\\u56de\\\\u5e94\\\\u6bd4\\\\u4e9a\\\\u8fea\\\\u201c\\\\u95ea\\\\u5145\\\\u201d\\\\uff1a\\\\u8ddf\\\\u6211\\\\u5b66\\\\u7684\\\\uff0c\\\\u6784\\\\u4e0d\\\\u6210\\\\u6311\\\\u6218\\\"}, \\\"links\\\": [{\\\"rel\\\": \\\"alternate\\\", \\\"type\\\": \\\"text/html\\\", \\\"href\\\": \\\"https://36kr.com/p/3769300040286980?f=rss\\\"}], \\\"link\\\": \\\"https://36kr.com/p/3769300040286980?f=rss\\\", \\\"published\\\": \\\"2026-04-16 18:42:24  +0800\\\", \\\"published_parsed\\\": [2026, 4, 16, 10, 42, 24, 3, 106, 0], \\\"summary\\\": \\\"<p>\\\\u6bcf\\\\u5929\\\\u51c0\\\\u8d5a\\\\u8d852\\\\u4e2a\\\\u5c0f\\\\u76ee\\\\u6807\\\\uff0c\\\\u201c\\\\u5b81\\\\u738b\\\\u201d\\\\u4e1a\\\\u7ee9\\\\u53c8\\\\u7206\\\\u4e86\\\\u3002</p>\\\\n  <p>\\\\u5254\\\\u9664\\\\u4e00\\\\u6b21\\\\u6027\\\\u6536\\\\u76ca\\\\u540e\\\\uff0c\\\\u516c\\\\u53f8\\\\u4e3b\\\\u4e1a\\\\u7684<strong>\\\\u5229\\\\u6da6\\\\u589e\\\\u901f\\\\u751a\\\\u81f3\\\\u8d85\\\\u8fc7\\\\u4e86\\\\u8425\\\\u6536\\\\u589e\\\\u901f</strong>\\\\u3002</p>\\\\n  <p>\\\\u8981\\\\u77e5\\\\u9053\\\\uff0c\\\\u5b81\\\\u5fb7\\\\u65f6\\\\u4ee32025\\\\u5e74\\\\u5168\\\\u5e74\\\\u51c0\\\\u5229\\\\u6da6722\\\\u4ebf\\\\uff0c\\\\u800c\\\\u52302026\\\\u5e74\\\\u4ec5\\\\u4ec5\\\\u4e00\\\\u4e2a\\\\u5b63\\\\u5ea6\\\\u5c31\\\\u5e72\\\\u4e86\\\\u8fd1207\\\\u4ebf\\\\u2014\\\\u2014\\\\u8fd9\\\\u8fd8\\\\u662f\\\\u5728\\\\u539f\\\\u6750\\\\u6599