\\u5e74\\\\u4e00\\\\u5b63\\\\u5ea6\\\\u5b81\\\\u5fb7\\\\u65f6\\\\u4ee3\\\\u7684\\\\u6263\\\\u975e\\\\u51c0\\\\u5229\\\\u6da6\\\\u4e3a180.93\\\\u4ebf\\\\u5143\\\\uff0c\\\\u540c\\\\u6bd4\\\\u589e\\\\u4e8652.95%\\\\u3002</p>\\\\n  <p>\\\\u8fd9\\\\u9879\\\\u6570\\\\u636e\\\\u5254\\\\u9664\\\\u4e86\\\\u4e00\\\\u6b21\\\\u6027\\\\u6536\\\\u76ca\\\\uff0c\\\\u53cd\\\\u6620\\\\u7684\\\\u662f\\\\u516c\\\\u53f8\\\\u4e3b\\\\u8425\\\\u4e1a\\\\u52a1\\\\u7684\\\\u771f\\\\u5b9e\\\\u76c8\\\\u5229\\\\u80fd\\\\u529b\\\\u589e\\\\u957f\\\\uff0c\\\\u5176\\\\u589e\\\\u901f\\\\u751a\\\\u81f3\\\\u6bd4\\\\u8425\\\\u6536\\\\u589e\\\\u901f\\\\u66f4\\\\u9ad8\\\\u3002</p>\\\\n  <p class=\\\\\\\"image-wrapper\\\\\\\"><img src=\\\\\\\"https://img.36krcdn.com/hsossms/20260416/v2_646fa7d3322f4c0989ba000aa73ee1fe@46958_oswg105771oswg945oswg454_img_000?x-oss-process=image/format,jpg/interlace,1\\\\\\\" /></p>\\\\n  <p>\\\\u5728\\\\u6210\\\\u672c\\\\u548c\\\\u8d39\\\\u7528\\\\u5c42\\\\u9762\\\\uff0c\\\\u5b81\\\\u5fb7\\\\u65f6\\\\u4ee3Q1\\\\u7684\\\\u8425\\\\u4e1a\\\\u6210\\\\u672c\\\\u4e3a970.86\\\\u4ebf\\\\u5143\\\\uff0c\\\\u540c\\\\u6bd4\\\\u589e\\\\u957f51.63%\\\\uff0c\\\\u589e\\\\u901f\\\\u4e0e\\\\u8425\\\\u6536\\\\u57fa\\\\u672c\\\\u540c\\\\u6b65\\\\u3002</p>\\\\n  <p>\\\\u56e0\\\\u6b64\\\\uff0c\\\\u516c\\\\u53f8\\\\u7684\\\\u6bdb\\\\u5229\\\\u6c34\\\\u5e73\\\\u4e5f\\\\u6ca1\\\\u6709\\\\u51fa\\\\u73b0\\\\u5927\\\\u7684\\\\u6ce2\\\\u52a8\\\\uff0c\\\\u8fd9\\\\u4e00\\\\u5b63\\\\u5ea6\\\\u7684\\\\u6bdb\\\\u5229\\\\u4e3a320.4\\\\u4ebf\\\\u5143\\\\uff0c\\\\u540c\\\\u6bd4\\\\u589e\\\\u957f55%\\\\u3002</p>\\\\n  <p>\\\\u540c\\\\u671f\\\\u7efc\\\\u5408\\\\u6bdb\\\\u5229\\\\u7387\\\\u4e3a24.8%\\\\uff0c\\\\u540c\\\\u6bd4\\\\u4e0a\\\\u6da80.4\\\\u4e2a\\\\u767e\\\\u5206\\\\u70b9\\\\uff0c\\\\u800c\\\\u73af\\\\u6bd4\\\\u8f83\\\\u53bb\\\\u5e74\\\\u56db\\\\u5b63\\\\u5ea6\\\\u4e0b\\\\u964d3.4\\\\u4e2a\\\\u767e\\\\u5206\\\\u70b9\\\\uff0c\\\\u4e3b\\\\u8981\\\\u539f\\\\u56e0\\\\u662f\\\\u53d7\\\\u5230\\\\u5b63\\\\u8282