INSERT INTO `article_storage` VALUES (6, 2216, '致癌阴影下的“中产货币”，Lululemon如何缝补信任裂痕？', '\"{\\\"title\\\": \\\"\\\\u81f4\\\\u764c\\\\u9634\\\\u5f71\\\\u4e0b\\\\u7684\\\\u201c\\\\u4e2d\\\\u4ea7\\\\u8d27\\\\u5e01\\\\u201d\\\\uff0cLululemon\\\\u5982\\\\u4f55\\\\u7f1d\\\\u8865\\\\u4fe1\\\\u4efb\\\\u88c2\\\\u75d5\\\\uff1f\\\", \\\"title_detail\\\": {\\\"type\\\": \\\"text/plain\\\", \\\"language\\\": null, \\\"base\\\": \\\"https://36kr.com/feed-article\\\", \\\"value\\\": \\\"\\\\u81f4\\\\u764c\\\\u9634\\\\u5f71\\\\u4e0b\\\\u7684\\\\u201c\\\\u4e2d\\\\u4ea7\\\\u8d27\\\\u5e01\\\\u201d\\\\uff0cLululemon\\\\u5982\\\\u4f55\\\\u7f1d\\\\u8865\\\\u4fe1\\\\u4efb\\\\u88c2\\\\u75d5\\\\uff1f\\\"}, \\\"links\\\": [{\\\"rel\\\": \\\"alternate\\\", \\\"type\\\": \\\"text/html\\\", \\\"href\\\": \\\"https://36kr.com/p/3769338726695680?f=rss\\\"}], \\\"link\\\": \\\"https://36kr.com/p/3769338726695680?f=rss\\\", \\\"published\\\": \\\"2026-04-16 19:33:20  +0800\\\", \\\"published_parsed\\\": [2026, 4, 16, 11, 33, 20, 3, 106, 0], \\\"summary\\\": \\\"<p class=\\\\\\\"image-wrapper\\\\\\\"><img src=\\\\\\\"https://img.36krcdn.com/hsossms/20260416/v2_037d3eb6533a4554b63b022cbff99b4b@46958_oswg548969oswg1080oswg567_img_000?x-oss-process=image/format,jpg/interlace,1\\\\\\\" /></p>\\\\n  <p><strong>\\\\u5728\\\\u63a8\\\\u52a8\\\\u4e1a\\\\u7ee9\\\\u5168\\\\u9762\\\\u590d\\\\u82cf\\\\u7684\\\\u8def\\\\u4e0a\\\\uff0cLululemon\\\\u518d\\\\u5ea6\\\\u906d\\\\u9047\\\\u4e25\\\\u91cd\\\\u6253\\\\u51fb\\\\u3002</strong></p>\\\\n  <p>\\\\u4e00\\\\u573a\\\\u4fe1\\\\u4efb\\\\u8ff7\\\\u96fe\\\\u76d6\\\\u5728\\\\u4e86\\\\u52a0\\\\u62ff\\\\u5927\\\\u8fd0\\\\u52a8\\\\u670d\\\\u9970\\\\u54c1\\\\u724c\\\\u5934\\\\u4e0a\\\\u3002\\\\u7f8e\\\\u56fd\\\\u5f53\\\\u5730\\\\u65f6\\\\u95f44\\\\u670813\\\\u65e5\\\\uff0c\\\\u7f8e\\\\u56fd\\\\u5f97\\\\u514b\\\\u8428\\\\u65af\\\\u5dde\\\\u603b\\\\u68c0\\\\u5bdf\\\\u957fKen Paxton\\\\u5ba3\\\\u5e03\\\\u5bf9Lululemon\\\\u5c55\\\\u5f00\\\\u8c03\\\\u67e5\\\\uff0c\\\\u56e0\\\\u5176\\\\u4ea7\\\\u54c1\\\\u4e2d\\\\u53ef\\\\u80fd\\\\u542b\\\\u6709\\\\u88ab\\\\u79f0\\\\u4e3a\\\\u201c\\\\u6c38\\\\u4e45\\\\u6027\\\\u5316\\\\u5b66\\\\u7269\\\\u201d\\\\u7684\\\\u5168\\\\u6c1f\\\\u53ca\\\\u591a\\\\u6c1f\\\\u70f7\\\\u57fa\\\\u7269\\\\u8d28\\\\uff08PFAS\\\\uff09\\\\u3002</p>\\\\n  <p>Ken Paxton\\\\u6307\\\\u51fa\\\\uff0c\\\\u6700\\\\u65b0\\\\u7814\\\\u7a76\\\\u7ed3\\\\u679c\\\\u4e0e\\\\u6d88\\\\u8d39\\\\u8005\\\\u62c5\\\\u5fe7\\\\u5f15\\\\u53d1\\\\u4e86\\\\u5916\\\\u754c\\\\u5bf9Lululemon\\\\u7684\\\\u7528\\\\u6599\\\\u8d28\\\\u7591\\\\u3002\\\\u5916\\\\u754c\\\\u62c5\\\\u5fe7Lululemon\\\\u670d\\\\u88c5\\\\u4e2d\\\\u7684\\\\u90e8\\\\u5206\\\\u5408\\\\u6210\\\\u6750\\\\u6599\\\\uff0c\\\\u662f\\\\u5426\\\\u4e0e\\\\u5185\\\\u5206\\\\u6ccc\\\\u7d0a\\\\u4e71\\\\u3001\\\\u4e0d\\\\u5b55\\\\u4e0d\\\\u80b2\\\\u3001\\\\u764c\\\\u75c7\\\\u53ca\\\\u5176\\\\u4ed6\\\\u5065\\\\u5eb7\\\\u98ce\\\\u9669\\\\u76f8\\\\u5173\\\\u3002</p>\\\\n  <p class=\\\\\\\"image-wrapper\\\\\\\"><img src=\\\\\\\"https://img.36krcdn.com/hsossms/20260416/v2_52edaf0c50de40f9915806fcfe970e48@46958_oswg699316oswg1052oswg647_img_000?x-oss-process=image/format,jpg/interlace,1\\\\\\\" /></p>\\\\n  <p>\\\\u8def\\\\u900f\\\\u793e\\\\u8865\\\\u5145\\\\u62a5\\\\u9053\\\\uff0c\\\\u5f97\\\\u514b\\\\u8428\\\\u65af\\\\u5dde\\\\u603b\\\\u68c0\\\\u5bdf\\\\u957f\\\\u529e\\\\u516c\\\\u5ba4\\\\u5c06\\\\u5bf9\\\\u7167\\\\u8be5\\\\u5dde\\\\u5b89\\\\u5168\\\\u6807\\\\u51c6\\\\uff0c\\\\u6838\\\\u67e5Lululemon\\\\u7684\\\\u68c0\\\\u6d4b\\\\u6d41\\\\u7a0b\\\\u3001\\\\u9650\\\\u7528\\\\u7269\\\\u8d28\\\\u6e05\\\\u5355\\\\u53ca\\\\u4f9b\\\\u5e94\\\\u94fe\\\\u7ba1\\\\u7406\\\\u63aa\\\\u65bd\\\\u3002Lululemon\\\\u7684\\\\u53d1\\\\u8a00\\\\u4eba\\\\u8868\\\\u793a\\\\u516c\\\\u53f8\\\\u5df2\\\\u7ecf\\\\u83b7\\\\u6089\\\\u6b64\\\\u6b21\\\\u8c03\\\\u67e5\\\\u5de5\\\\u4f5c\\\\uff0c\\\\u5e76\\\\u6b63\\\\u5728\\\\u914d\\\\u5408\\\\u3002</p>\\\\n  <p>\\\\u6d88\\\\u606f\\\\u4e00\\\\u51fa\\\\u8206\\\\u8bba\\\\u54d7\\\\u7136\\\\u300