\\u6d4e\\\\u89c2\\\\u5bdf\\\", \\\"author_detail\\\": {\\\"name\\\": \\\"\\\\u4f53\\\\u575b\\\\u7ecf\\\\u6d4e\\\\u89c2\\\\u5bdf\\\"}, \\\"content\\\": [{\\\"type\\\": \\\"text/plain\\\", \\\"language\\\": null, \\\"base\\\": \\\"https://36kr.com/feed-article\\\", \\\"value\\\": \\\"Lululemon\\\\u56e0PFAS\\\\u88ab\\\\u8c03\\\\u67e5\\\\uff0c\\\\u54c1\\\\u724c\\\\u4fe1\\\\u4efb\\\\u5371\\\\u673a\\\\u52a0\\\\u5267\\\\u3002\\\"}]}\"', '2026-04-17 15:06:47');
