INSERT INTO `article_storage` VALUES (8, 2243, '香港国际创科展及春季电子产品展开幕', '\"{\\\"title\\\": \\\"\\\\u9999\\\\u6e2f\\\\u56fd\\\\u9645\\\\u521b\\\\u79d1\\\\u5c55\\\\u53ca\\\\u6625\\\\u5b63\\\\u7535\\\\u5b50\\\\u4ea7\\\\u54c1\\\\u5c55\\\\u5f00\\\\u5e55\\\", \\\"title_detail\\\": {\\\"type\\\": \\\"text/plain\\\", \\\"language\\\": null, \\\"base\\\": \\\"https://news.baidu.com/n?cmd=1&class=gangaotai&tn=rss\\\", \\\"value\\\": \\\"\\\\u9999\\\\u6e2f\\\\u56fd\\\\u9645\\\\u521b\\\\u79d1\\\\u5c55\\\\u53ca\\\\u6625\\\\u5b63\\\\u7535\\\\u5b50\\\\u4ea7\\\\u54c1\\\\u5c55\\\\u5f00\\\\u5e55\\\"}, \\\"links\\\": [{\\\"rel\\\": \\\"alternate\\\", \\\"type\\\": \\\"text/html\\\", \\\"href\\\": \\\"http://baijiahao.baidu.com/s?id=1862496611190385766\\\"}], \\\"link\\\": \\\"http://baijiahao.baidu.com/s?id=1862496611190385766\\\", \\\"published\\\": \\\"2026-04-16T14:51:58.000Z\\\", \\\"published_parsed\\\": [2026, 4, 16, 14, 51, 58, 3, 106, 0], \\\"source\\\": {}, \\\"authors\\\": [{}], \\\"author\\\": \\\"\\\", \\\"summary\\\": \\\"<a href=\\\\\\\"http://baijiahao.baidu.com/s?id=1862496611190385766\\\\\\\" target=\\\\\\\"_blank\\\\\\\"><img border=\\\\\\\"0\\\\\\\" src=\\\\\\\"http://t1.baidu.com/it/u=http%3A%2F%2Ft10.baidu.com%2Fit%2Fu%3D2801954284%2C294163664%26fm%3D30%26app%3D106%26f%3DJPEG%3Fw%3D312%26h%3D208%26s%3DF294198CE40158EE5EAB2CDB0300C0BA&amp;fm=30\\\\\\\" /></a><br />\\\\u56fe\\\\u4e3a\\\\u89c2\\\\u4f17\\\\u5728\\\\u53c2\\\\u89c2\\\\u667a\\\\u6167\\\\u9999\\\\u6e2f\\\\u5c55\\\\u9986\\\\u3002\\\\u4e2d\\\\u65b0\\\\u793e\\\\u8bb0\\\\u8005\\\\u5f20\\\\u7965\\\\u6bc5\\\\u6444\\\\u672c\\\\u62a5\\\\u9999\\\\u6e2f4\\\\u670814\\\\u65e5\\\\u7535(\\\\u8bb0\\\\u8005\\\\u51af\\\\u5b66\\\\u77e5)\\\\u9999\\\\u6e2f\\\\u56fd\\\\u9645\\\\u521b\\\\u79d1\\\\u5c55\\\\u53ca\\\\u6625\\\\u5b63\\\\u7535\\\\u5b50\\\\u4ea7\\\\u54c1\\\\u5c5514\\\\u65e5\\\\u5728\\\\u9999\\\\u6e2f\\\\u4f1a\\\\u8bae\\\\u5c55\\\\u89c8\\\\u4e2d\\\\u5fc3\\\\u5f00\\\\u5e55\\\\u3002\\\\u4e24\\\\u5c55\\\\u6c47\\\\u805a\\\\u73af\\\\u7403\\\\u9876\\\\u5c16\\\\u521b\\\\u79d1\\\\u65b9\\\\u6848\\\\u3001\\\\u4eba\\\\u5de5\\\\u667a\\\\u80fd\\\\u6280\\\\u672f\\\\u53ca\\\\u7535\\\\u5b50\\\\u4ea7\\\\u54c1\\\\uff0c\\\\u5438\\\\u5f15\\\\u6765\\\\u81ea2<br />\\\", \\\"summary_detail\\\": {\\\"type\\\": \\\"text/html\\\", \\\"language\\\": null, \\\"base\\\": \\\"https://news.baidu.com/n?cmd=1&class=gangaotai&tn=rss\\\", \\\"value\\\": \\\"<a href=\\\\\\\"http://baijiahao.baidu.com/s?id=1862496611190385766\\\\\\\" target=\\\\\\\"_blank\\\\\\\"><img border=\\\\\\\"0\\\\\\\" src=\\\\\\\"http://t1.baidu.com/it/u=http%3A%2F%2Ft10.baidu.com%2Fit%2Fu%3D2801954284%2C294163664%26fm%3D30%26app%3D106%26f%3DJPEG%3Fw%3D312%26h%3D208%26s%3DF294198CE40158EE5EAB2CDB0300C0BA&amp;fm=30\\\\\\\" /></a><br />\\\\u56fe\\\\u4e3a\\\\u89c2\\\\u4f17\\\\u5728\\\\u53c2\\\\u89c2\\\\u667a\\\\u6167\\\\u9999\\\\u6e2f\\\\u5c55\\\\u9986\\\\u3002\\\\u4e2d\\\\u65b0\\\\u793e\\\\u8bb0\\\\u8005\\\\u5f20\\\\u7965\\\\u6bc5\\\\u6444\\\\u672c\\\\u62a5\\\\u9999\\\\u6e2f4\\\\u670814\\\\u65e5\\\\u7535(\\\\u8bb0\\\\u8005\\\\u51af\\\\u5b66\\\\u77e5)\\\\u9999\\\\u6e2f\\\\u56fd\\\\u9645\\\\u521b\\\\u79d1\\\\u5c55\\\\u53ca\\\\u6625\\\\u5b63\\\\u7535\\\\u5b50\\\\u4ea7\\\\u54c1\\\\u5c5514\\\\u65e5\\\\u5728\\\\u9999\\\\u6e2f\\\\u4f1a\\\\u8bae\\\\u5c55\\\\u89c8\\\\u4e2d\\\\u5fc3\\\\u5f00\\\\u5e55\\\\u3002\\\\u4e24\\\\u5c55\\\\u6c47\\\\u805a\\\\u73af\\\\u7403\\\\u9876\\\\u5c16\\\\u521b\\\\u79d1\\\\u65b9\\\\u6848\\\\u3001\\\\u4eba\\\\u5de5\\\\u667a\\\\u80fd\\\\u6280\\\\u672f\\\\u53ca\\\\u7535\\\\u5b50\\\\u4ea7\\\\u54c1\\\\uff0c\\\\u5438\\\\u5f15\\\\u6765\\\\u81ea2<br />\\\"}}\"', '2026-04-17 15:07:30');
INSERT INTO `article_storage` VALUES (9, 2252, '36氪首发 | “华为天才少年”创业连融超4亿元，做新一代推理芯片重构显存成本', '{\"link\": \"https://36kr.com/p/3770363954954755?f=rss\", \"links\": [{\"rel\": \"alternate\", \"href\": \"https://36kr.com/p/3770363954954755?f=rss\", \"type\": \"text/html\"}], \"title\": \"36氪首发 | “华为天才少年”创业连融超4亿元，做新一代推理芯片重构显存成本\", \"source\": {\"title\": \"36氪\"}, \"summary\": \"<p>作者&nbsp;|&nbsp;乔钰杰</p>\\n  <p>编辑&nbsp;|&nbsp;袁斯来</p>\\n  <p>硬氪获悉，国内全自研GPGPU创新企业「北京行云集成电路有限公司」（以下简称“行云”）宣布连续完成Pre-A及Pre-A+多轮融资，融资金额超4亿元人民币。五源资本、赛富投资基金、春华资本联合领投，以及北京、江苏等地方国资、佰维存储（688525）、金沙江联合带动知名GPU企业创始人家办、创维资本等产业资本跟投。云岫资本连续多轮服务并担任下一轮独家融资财务顾问。</p>\\n  <p>北京行云集成电路有限公司成立于2023年8月，专注针对大模型的新一代推理芯片，致力于使用非3D DRAM架构打造超大显存规格、CUDA兼容的全自研GPGPU产品，推动AI大模型推理的普惠化。</p>\\n  <p>行云创始人季宇博士，清华大学计算机系博士，“华为天才少年”计划的一员，曾在华为海思深度参与昇腾AI芯片的编译器与架构研发。CTO余洪敏博士，中科院半导体所博士，曾主导百度昆仑芯、海思昇腾等多款芯片的研发与量产，拥有十余款芯片成功流片经验。</p>\\n  <p>当前，在大模型架构持续演进的背景下，算力系统的瓶颈正在发生结构性变化。</p>\\n  <p>季宇在接受硬氪采访时表示，当前算法侧的演进正在重塑硬件设计逻辑。以MoE（Mixture of Experts）为代表的稀疏模型，在计算效率上更具优势，但需要预先加载更多专家参数，使得整体对内存容量的需求显著高于传统Transformer稠密模型。</p>\\n  <p><strong>大模型（千亿/万亿参数）的显存需求已从GB级跃升至TB级，这一过程中，系统成本结构也随之重构——按GB计价的显存成本，正逐步超过算力芯片本身，成为主导项。因此，“降本的关键已经不在算力，而在显存”季宇称。</strong></p>\\n  <p>基于这一判断，行云选择了一条与主流路径不同的技术路线：<strong>放弃成本高昂的HBM（高带宽内存），转而采用LPDDR乃至NAND（SSD颗粒）等更低成本的存储介质作为显存介质。通过介质替换，使显存成本降低1到2个数量级。</strong></p>\\n  <p>但低成本介质也意味着单颗粒带宽较低。为弥补这一短板，行云在架构上采用多颗粒、多通道并行的设计，通过规模化堆叠将整体带宽提升至TB级别，以满足大模型推理对数据吞吐的需求。</p>\\n  <p>季宇表示，随着稀疏化和MoE架构的发展，模型对带宽的绝对需求正在下降，系统设计不再需要一味追求极致带宽，而是可以通过软硬件协同，实现成本与效率之间的平衡。</p>\\n  <p>这种思路也体现在行云的整体技术策略中。季宇强调，公司真正的稀缺性并不在单一芯片指标，而在于系统级的设计能力。通过诸如Prefill/Decode分离（PD分离）、KV Cache稀疏化等工程手段，行云能够更灵活地适配AI应用形态的快速变化，从早期的Chatbot到当前逐步兴起的Agent场景，降低因芯片研发周期较长所带来的技术滞后风险。</p>\\n  <p>产品验证层面，行云此前推出的“褐蚁一体机”，已尝试用CPU与通用内存构建低成本推理方案，验证稀疏模型在非高端硬件上的可行性。目前，该方案已在DeepSeek的本地化部署场景中落地。</p>\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260417/v2_77f14aff1a16446786fe983d4be90c1c@5920579_oswg160747oswg441oswg588_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\n  <p class=\\\"img-desc\\\">（图源/企业）</p>\\n  <p>接下来，公司将把重心转向自研芯片的推进。季宇表示，公司今年的核心目标是完成芯片流片，并尽快推向市场，以芯片产品作为商业化的主要抓手。</p>\\n  <p>当下，Open Claw的现象级传播也揭示了市场对消费级硬件承载高质量AI的巨大需求。<strong>季宇表示，行云希望通过其芯片产品，将低成本、高质量的万亿级模型算力真正落地到如龙虾机等端侧设备，突破当前端侧仅能运行100B小模型的局限，为消费电子市场打开新的想象空间。</strong></p>\\n  <p>CTO余洪敏表示，行云的设计优先级已从追求单芯片极致性能，转变为从板级系统角度追求可扩展性与供应链稳定性。通过分布式设计和采用成熟工艺与低成本存储，在系统层面实现成本最优与性能体验一致，这是公司实现算力普惠的重要基础。</p>\\n  <p>&nbsp;</p>\\n  <p><strong>投资方观点</strong></p>\\n  <p><strong>峰瑞资本副总裁李罡表示：</strong>作为天使轮投资人，行云团队从23年创业开始，对AI芯片（特别是大模型环境下的AI芯片）有着极为前瞻的视角和思路。在近三年的模型和应用的快速变化中，我们看到行云针对下一代通用大模型的芯片方案和前瞻的设计思想，不断得到验证，始终领先时代半步。</p>\\n  <p><strong>五源资本表示：</strong>行云是AI芯片领域少有的‘第一性原理’思考者，季宇博士24年就前瞻性地洞察到MoE稀疏架构下硬件瓶颈从算力向显存迁移的结构性转变——放弃HBM、以LPDDR乃至NAND重构显存成本，不是渐进优化，而是通过系统级的软硬件协同设计能力推动行业范式创新。2026年以来随着AI模型coding和agent能力持续增强，AI推理需求爆发，OpenClaw等Agent的现象级破圈，正在将推理算力需求从云端拉向多端，从程序员推向大众，高效低成本的推理能力成为行业刚需。伴随未来推理需求的指数级增长，行云的技术路径将成为推动算力普惠的重要基础设施。</p>\\n  <p><strong>赛富投资基金负责科技赛道的管理合伙人蒋驰华表示：</strong>在AI大模型向万亿参数演进的过程中，降本的关键已经不在算力，而在显存和系统的架构，特别是在国产算力受限的前提下。季宇和行云团队展现出了罕见的系统级工程视野，他们跳出了盲目堆砌HBM的行业定式，通过LPDDR/NAND等介质替换与并行架构设计，将显存和系统成本打下来一到两个数量级，进而实现单Token成本极值，符合行业演进的方向。我们始终聚焦AI与具身智能领域的底层颠覆者。行云兼具前瞻的架构创新与扎实的落地能力，赛富很荣幸能在这一轮重仓支持。我们期待行云的新一代推理芯片彻底重构算力成本模型，真正实现大模型推理在云端与端侧的全面普惠。</p>\\n  <p><strong>春华资本表示：</strong>在国产算力生态加速构建的大背景下。行云敏锐地将设计重心锚定在显存成本重构上，以LPDDR与NAND替代HBM、通过多通道并行架构弥补单颗粒带宽不足，本质上是在重新定义推理芯片的成本架构。季宇博士对AI芯片架构的演进方向有着超越行业惯性的深度思考，他对‘降本关键在显存而非算力’的判断，始终领先行业共识半步，且每一步都在被市场持续验证；余洪敏博士作为从海思昇腾到百度昆仑芯一路走来的芯片老兵，对芯片从设计到量产的每一个环节都有实战积累。这种‘敢想’与‘能做’的结合，让行云具备了从架构创新到产品交付的完整闭环能力。我们期待行云的首颗自研芯片顺利流片，开启AI推理算力的新一轮成本革命。</p>\\n  <p><strong>佰维存储科技股份有限公司副总经理王灿：</strong>在大模型从通用AI向Agent形态演进的发展阶段，季宇博士展现了极具前瞻性的系统级洞察。他精准地识别出：大模型推理的结构性瓶颈已不再仅仅是算力本身，而是制约规模化落地的更低成本的存储。行云的核心逻辑非常清晰——通过介质替换与架构创新，以低成本的LPDDR乃至NAND介质挑战昂贵的HBM霸权，这不仅是物理介质的更迭，更是对大模型推理成本结构的底层重构。围绕这一核心路径，行云构建了极致的软硬件协同设计，通过PD分离、分布式扩展等手段，在系统层面实现了性能与成本的平衡。芯片行业，工程经验决定了从‘实验室架构’到‘商业化量产’的跨度。行云团队在昇腾、昆仑芯等顶尖项目上积淀的深厚流片与量产经验，是其确定性的来源。在AI Agent爆发的当下，我坚信行云能够真正击穿算力成本，让高质量的万亿级模型实现真正的算力普惠。</p>\", \"published\": \"2026-04-17 11:33:56  +0800\", \"title_detail\": {\"base\": \"https://36kr.com/feed\", \"type\": \"text/plain\", \"value\": \"36氪首发 | “华为天才少年”创业连融超4亿元，做新一代推理芯片重构显存成本\", \"language\": null}, \"summary_detail\": {\"base\": \"https://36kr.com/feed\", \"type\": \"text/html\", \"value\": \"<p>作者&nbsp;|&nbsp;乔钰杰</p>\\n  <p>编辑&nbsp;|&nbsp;袁斯来</p>\\n  <p>硬氪获悉，国内全自研GPGPU创新企业「北京行云集成电路有限公司」（以下简称“行云”）宣布连续完成Pre-A及Pre-A+多轮融资，融资金额超4亿元人民币。五源资本、赛富投资基金、春华资本联合领投，以及北京、江苏等地方国资、佰维存储（688525）、金沙江联合带动知名GPU企业创始人家办、创维资本等产业资本跟投。云岫资本连续多轮服务并担任下一轮独家融资财务顾问。</p>\\n  <p>北京行云集成电路有限公司成立于2023年8月，专注针对大模型的新一代推理芯片，致力于使用非3D DRAM架构打造超大显存规格、CUDA兼容的全自研GPGPU产品，推动AI大模型推理的普惠化。</p>\\n  <p>行云创始人季宇博士，清华大学计算机系博士，“华为天才少年”计划的一员，曾在华为海思深度参与昇腾AI芯片的编译器与架构研发。CTO余洪敏博士，中科院半导体所博士，曾主导百度昆仑芯、海思昇腾等多款芯片的研发与量产，拥有十余款芯片成功流片经验。</p>\\n  <p>当前，在大模型架构持续演进的背景下，算力系统的瓶颈正在发生结构性变化。</p>\\n  <p>季宇在接受硬氪采访时表示，当前算法侧的演进正在重塑硬件设计逻辑。以MoE（Mixture of Experts）为代表的稀疏模型，在计算效率上更具优势，但需要预先加载更多专家参数，使得整体对内存容量的需求显著高于传统Transformer稠密模型。</p>\\n  <p><strong>大模型（千亿/万亿参数）的显存需求已从GB级跃升至TB级，这一过程中，系统成本结构也随之重构——按GB计价的显存成本，正逐步超过算力芯片本身，成为主导项。因此，“降本的关键已经不在算力，而在显存”季宇称。</strong></p>\\n  <p>基于这一判断，行云选择了一条与主流路径不同的技术路线：<strong>放弃成本高昂的HBM（高带宽内存），转而采用LPDDR乃至NAND（SSD颗粒）等更低成本的存储介质作为显存介质。通过介质替换，使显存成本降低1到2个数量级。</strong></p>\\n  <p>但低成本介质也意味着单颗粒带宽较低。为弥补这一短板，行云在架构上采用多颗粒、多通道并行的设计，通过规模化堆叠将整体带宽提升至TB级别，以满足大模型推理对数据吞吐的需求。</p>\\n  <p>季宇表示，随着稀疏化和MoE架构的发展，模型对带宽的绝对需求正在下降，系统设计不再需要一味追求极致带宽，而是可以通过软硬件协同，实现成本与效率之间的平衡。</p>\\n  <p>这种思路也体现在行云的整体技术策略中。季宇强调，公司真正的稀缺性并不在单一芯片指标，而在于系统级的设计能力。通过诸如Prefill/Decode分离（PD分离）、KV Cache稀疏化等工程手段，行云能够更灵活地适配AI应用形态的快速变化，从早期的Chatbot到当前逐步兴起的Agent场景，降低因芯片研发周期较长所带来的技术滞后风险。</p>\\n  <p>产品验证层面，行云此前推出的“褐蚁一体机”，已尝试用CPU与通用内存构建低成本推理方案，验证稀疏模型在非高端硬件上的可行性。目前，该方案已在DeepSeek的本地化部署场景中落地。</p>\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260417/v2_77f14aff1a16446786fe983d4be90c1c@5920579_oswg160747oswg441oswg588_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\n  <p class=\\\"img-desc\\\">（图源/企业）</p>\\n  <p>接下来，公司将把重心转向自研芯片的推进。季宇表示，公司今年的核心目标是完成芯片流片，并尽快推向市场，以芯片产品作为商业化的主要抓手。</p>\\n  <p>当下，Open Claw的现象级传播也揭示了市场对消费级硬件承载高质量AI的巨大需求。<strong>季宇表示，行云希望通过其芯片产品，将低成本、高质量的万亿级模型算力真正落地到如龙虾机等端侧设备，突破当前端侧仅能运行100B小模型的局限，为消费电子市场打开新的想象空间。</strong></p>\\n  <p>CTO余洪敏表示，行云的设计优先级已从追求单芯片极致性能，转变为从板级系统角度追求可扩展性与供应链稳定性。通过分布式设计和采用成熟工艺与低成本存储，在系统层面实现成本最优与性能体验一致，这是公司实现算力普惠的重要基础。</p>\\n  <p>&nbsp;</p>\\n  <p><strong>投资方观点</strong></p>\\n  <p><strong>峰瑞资本副总裁李罡表示：</strong>作为天使轮投资人，行云团队从23年创业开始，对AI芯片（特别是大模型环境下的AI芯片）有着极为前瞻的视角和思路。在近三年的模型和应用的快速变化中，我们看到行云针对下一代通用大模型的芯片方案和前瞻的设计思想，不断得到验证，始终领先时代半步。</p>\\n  <p><strong>五源资本表示：</strong>行云是AI芯片领域少有的‘第一性原理’思考者，季宇博士24年就前瞻性地洞察到MoE稀疏架构下硬件瓶颈从算力向显存迁移的结构性转变——放弃HBM、以LPDDR乃至NAND重构显存成本，不是渐进优化，而是通过系统级的软硬件协同设计能力推动行业范式创新。2026年以来随着AI模型coding和agent能力持续增强，AI推理需求爆发，OpenClaw等Agent的现象级破圈，正在将推理算力需求从云端拉向多端，从程序员推向大众，高效低成本的推理能力成为行业刚需。伴随未来推理需求的指数级增长，行云的技术路径将成为推动算力普惠的重要基础设施。</p>\\n  <p><strong>赛富投资基金负责科技赛道的管理合伙人蒋驰华表示：</strong>在AI大模型向万亿参数演进的过程中，降本的关键已经不在算力，而在显存和系统的架构，特别是在国产算力受限的前提下。季宇和行云团队展现出了罕见的系统级工程视野，他们跳出了盲目堆砌HBM的行业定式，通过LPDDR/NAND等介质替换与并行架构设计，将显存和系统成本打下来一到两个数量级，进而实现单Token成本极值，符合行业演进的方向。我们始终聚焦AI与具身智能领域的底层颠覆者。行云兼具前瞻的架构创新与扎实的落地能力，赛富很荣幸能在这一轮重仓支持。我们期待行云的新一代推理芯片彻底重构算力成本模型，真正实现大模型推理在云端与端侧的全面普惠。</p>\\n  <p><strong>春华资本表示：</strong>在国产算力生态加速构建的大背景下。行云敏锐地将设计重心锚定在显存成本重构上，以LPDDR与NAND替代HBM、通过多通道并行架构弥补单颗粒带宽不足，本质上是在重新定义推理芯片的成本架构。季宇博士对AI芯片架构的演进方向有着超越行业惯性的深度思考，他对‘降本关键在显存而非算力’的判断，始终领先行业共识半步，且每一步都在被市场持续验证；余洪敏博士作为从海思昇腾到百度昆仑芯一路走来的芯片老兵，对芯片从设计到量产的每一个环节都有实战积累。这种‘敢想’与‘能做’的结合，让行云具备了从架构创新到产品交付的完整闭环能力。我们期待行云的首颗自研芯片顺利流片，开启AI推理算力的新一轮成本革命。</p>\\n  <p><strong>佰维存储科技股份有限公司副总经理王灿：</strong>在大模型从通用AI向Agent形态演进的发展阶段，季宇博士展现了极具前瞻性的系统级洞察。他精准地识别出：大模型推理的结构性瓶颈已不再仅仅是算力本身，而是制约规模化落地的更低成本的存储。行云的核心逻辑非常清晰——通过介质替换与架构创新，以低成本的LPDDR乃至NAND介质挑战昂贵的HBM霸权，这不仅是物理介质的更迭，更是对大模型推理成本结构的底层重构。围绕这一核心路径，行云构建了极致的软硬件协同设计，通过PD分离、分布式扩展等手段，在系统层面实现了性能与成本的平衡。芯片行业，工程经验决定了从‘实验室架构’到‘商业化量产’的跨度。行云团队在昇腾、昆仑芯等顶尖项目上积淀的深厚流片与量产经验，是其确定性的来源。在AI Agent爆发的当下，我坚信行云能够真正击穿算力成本，让高质量的万亿级模型实现真正的算力普惠。</p>\", \"language\": null}, \"published_parsed\": [2026, 4, 17, 3, 33, 56, 4, 107, 0]}', '2026-04-17 15:07:37');
INSERT INTO `article_storage` VALUES (10, 2253, '最前线｜大疆发布 Pocket 4 并预告双摄版本，起售价下调500元', '{\"link\": \"https://36kr.com/p/3769604011885316?f=rss\", \"links\": [{\"rel\": \"alternate\", \"href\": \"https://36kr.com/p/3769604011885316?f=rss\", \"type\": \"text/html\"}], \"title\": \"最前线｜大疆发布 Pocket 4 并预告双摄版本，起售价下调500元\", \"source\": {\"title\": \"36氪\"}, \"summary\": \"<p>文｜张子怡</p>\\n  <p>编辑｜袁斯来</p>\\n  <p>4月16日，大疆正式发布全新一英寸口袋云台相机Osmo Pocket 4。</p>\\n  <p>作为大疆影像产品线中的现象级单品，本代产品在维持便携形态的基础上，通过提升影像规格并降低售价，以应对日益激烈的短视频硬件市场竞争。</p>\\n  <p>影像性能是此次升级的核心。Pocket 4搭载了全新一英寸CMOS，动态范围提升至14级，并支持10-bit D-Log专业色彩模式。</p>\\n  <p>最显著的性能跨越体现在高帧率拍摄上，设备支持4K/240fps慢动作录制，这一指标已媲美万元级专业影像设备。针对人像拍摄这一核心场景，Pocket 4优化了肤色调校算法，并新增内置美肤滤镜以及支持三级色温调节的外置补光灯配件。</p>\\n  <p>此外，针对前代产品存储依赖存储卡的痛点，大疆此次内置了107GB存储空间，并支持800MB/s的导出速度。</p>\\n  <p>在智能功能上，升级后的智能跟随7.0算法配合2倍无损变焦，解决了远距离追焦的精准度问题。智能对焦系统也引入了“登记主角优先”模式，确保在复杂环境下已登记的拍摄主体始终处于焦点中心。</p>\\n  <p>大疆同步预告了2026年的新品计划——搭载双摄影像系统的Osmo Pocket 4P。有分析认为，4P版本的推出意在通过物理焦段的覆盖，彻底解决口袋云台相机在长焦端的劣势，以此防守影石（Insta360）Luna等潜在竞品的冲击。</p>\\n  <p>价格策略是本次产品发布的另一大重点。Pocket 4标准套装售价为2999元，全能套装售价3799元，分别较上一代Pocket 3的首发价格降低了500元和700元。这种“增配降价”的打法在云台相机市场极其罕见。</p>\\n  <p>此次定价调整背后也是行业格局的剧变。IDC数据显示，2025年度全球云台相机出货量同比增长超100%，这一高增速市场已吸引了包括影石、GoPro在内的实力厂商跟进，甚至手机厂商如OPPO也已立项对标产品。</p>\\n  <p>大疆选择在此时主动挑起价格战，旨在利用其成熟的供应链规模效应压低行业利润率，拉高新入局者的门槛。随着Pocket 4的发布，手持影像设备行业正从单纯的“卷参数”转向“卷价格与专业化转型”并行的下半场。</p>\", \"published\": \"2026-04-17 09:00:53  +0800\", \"title_detail\": {\"base\": \"https://36kr.com/feed\", \"type\": \"text/plain\", \"value\": \"最前线｜大疆发布 Pocket 4 并预告双摄版本，起售价下调500元\", \"language\": null}, \"summary_detail\": {\"base\": \"https://36kr.com/feed\", \"type\": \"text/html\", \"value\": \"<p>文｜张子怡</p>\\n  <p>编辑｜袁斯来</p>\\n  <p>4月16日，大疆正式发布全新一英寸口袋云台相机Osmo Pocket 4。</p>\\n  <p>作为大疆影像产品线中的现象级单品，本代产品在维持便携形态的基础上，通过提升影像规格并降低售价，以应对日益激烈的短视频硬件市场竞争。</p>\\n  <p>影像性能是此次升级的核心。Pocket 4搭载了全新一英寸CMOS，动态范围提升至14级，并支持10-bit D-Log专业色彩模式。</p>\\n  <p>最显著的性能跨越体现在高帧率拍摄上，设备支持4K/240fps慢动作录制，这一指标已媲美万元级专业影像设备。针对人像拍摄这一核心场景，Pocket 4优化了肤色调校算法，并新增内置美肤滤镜以及支持三级色温调节的外置补光灯配件。</p>\\n  <p>此外，针对前代产品存储依赖存储卡的痛点，大疆此次内置了107GB存储空间，并支持800MB/s的导出速度。</p>\\n  <p>在智能功能上，升级后的智能跟随7.0算法配合2倍无损变焦，解决了远距离追焦的精准度问题。智能对焦系统也引入了“登记主角优先”模式，确保在复杂环境下已登记的拍摄主体始终处于焦点中心。</p>\\n  <p>大疆同步预告了2026年的新品计划——搭载双摄影像系统的Osmo Pocket 4P。有分析认为，4P版本的推出意在通过物理焦段的覆盖，彻底解决口袋云台相机在长焦端的劣势，以此防守影石（Insta360）Luna等潜在竞品的冲击。</p>\\n  <p>价格策略是本次产品发布的另一大重点。Pocket 4标准套装售价为2999元，全能套装售价3799元，分别较上一代Pocket 3的首发价格降低了500元和700元。这种“增配降价”的打法在云台相机市场极其罕见。</p>\\n  <p>此次定价调整背后也是行业格局的剧变。IDC数据显示，2025年度全球云台相机出货量同比增长超100%，这一高增速市场已吸引了包括影石、GoPro在内的实力厂商跟进，甚至手机厂商如OPPO也已立项对标产品。</p>\\n  <p>大疆选择在此时主动挑起价格战，旨在利用其成熟的供应链规模效应压低行业利润率，拉高新入局者的门槛。随着Pocket 4的发布，手持影像设备行业正从单纯的“卷参数”转向“卷价格与专业化转型”并行的下半场。</p>\", \"language\": null}, \"published_parsed\": [2026, 4, 17, 1, 0, 53, 4, 107, 0]}', '2026-04-17 15:07:38');
INSERT INTO `article_storage` VALUES (11, 2256, 'A股三大指数收盘涨跌不一，源杰科技登顶A股新股王', '{\"link\": \"https://36kr.com/newsflashes/3770569580380679?f=rss\", \"links\": [{\"rel\": \"alternate\", \"href\": \"https://36kr.com/newsflashes/3770569580380679?f=rss\", \"type\": \"text/html\"}], \"title\": \"A股三大指数收盘涨跌不一，源杰科技登顶A股新股王\", \"source\": {\"title\": \"36氪\"}, \"summary\": \"36氪获悉，A股三大指数收盘涨跌不一，沪指跌0.1%，深成指涨0.6%，创业板指涨1.43%；CPO、地产、传媒板块领涨，源杰科技涨超10%，股价超越贵州茅台，登顶A股新股王，西藏城投涨超6%，中国电影涨5%；白酒、制药、贵金属板块走弱，贵州茅台、广济药业跌超3%，西部黄金跌超2%。\", \"published\": \"2026-04-17 15:01:43  +0800\", \"title_detail\": {\"base\": \"https://36kr.com/feed\", \"type\": \"text/plain\", \"value\": \"A股三大指数收盘涨跌不一，源杰科技登顶A股新股王\", \"language\": null}, \"summary_detail\": {\"base\": \"https://36kr.com/feed\", \"type\": \"text/html\", \"value\": \"36氪获悉，A股三大指数收盘涨跌不一，沪指跌0.1%，深成指涨0.6%，创业板指涨1.43%；CPO、地产、传媒板块领涨，源杰科技涨超10%，股价超越贵州茅台，登顶A股新股王，西藏城投涨超6%，中国电影涨5%；白酒、制药、贵金属板块走弱，贵州茅台、广济药业跌超3%，西部黄金跌超2%。\", \"language\": null}, \"published_parsed\": [2026, 4, 17, 7, 1, 43, 4, 107, 0]}', '2026-04-17 15:07:41');
