INSERT INTO `article_storage` VALUES (13, 2259, '瑞幸已为即享咖啡小罐子登记作品著作权', '{\"link\": \"https://36kr.com/newsflashes/3770552174985728?f=rss\", \"links\": [{\"rel\": \"alternate\", \"href\": \"https://36kr.com/newsflashes/3770552174985728?f=rss\", \"type\": \"text/html\"}], \"title\": \"瑞幸已为即享咖啡小罐子登记作品著作权\", \"source\": {\"title\": \"36氪\"}, \"summary\": \"36氪获悉，爱企查App显示，瑞幸咖啡（中国）有限公司已为“瑞幸即享咖啡小罐子”“瑞幸冻干即溶咖啡系列”“瑞幸即享咖啡IP形象”等美术作品登记作品著作权。\", \"published\": \"2026-04-17 14:44:01  +0800\", \"title_detail\": {\"base\": \"https://36kr.com/feed\", \"type\": \"text/plain\", \"value\": \"瑞幸已为即享咖啡小罐子登记作品著作权\", \"language\": null}, \"summary_detail\": {\"base\": \"https://36kr.com/feed\", \"type\": \"text/html\", \"value\": \"36氪获悉，爱企查App显示，瑞幸咖啡（中国）有限公司已为“瑞幸即享咖啡小罐子”“瑞幸冻干即溶咖啡系列”“瑞幸即享咖啡IP形象”等美术作品登记作品著作权。\", \"language\": null}, \"published_parsed\": [2026, 4, 17, 6, 44, 1, 4, 107, 0]}', '2026-04-17 15:07:43');
INSERT INTO `article_storage` VALUES (14, 2262, '机构：受存储价格大幅上涨冲击低端市场影响，2025年下半年ODM/IDH智能手机出货量同比下滑10%', '{\"link\": \"https://36kr.com/newsflashes/3770533304632066?f=rss\", \"links\": [{\"rel\": \"alternate\", \"href\": \"https://36kr.com/newsflashes/3770533304632066?f=rss\", \"type\": \"text/html\"}], \"title\": \"机构：受存储价格大幅上涨冲击低端市场影响，2025年下半年ODM/IDH智能手机出货量同比下滑10%\", \"source\": {\"title\": \"36氪\"}, \"summary\": \"36氪获悉，据Counterpoint咨询，2025年下半年存储价格大幅上涨，给全球智能手机行业带来了显著的成本压力，尤其冲击了低端市场。2025年下半年售价150美元以下的智能手机销量同比下滑11%。由于OEM的中低端机型出货量高度依赖ODM/IDH，这场由成本上涨驱动的市场下行趋势不可避免地传导至ODM-IDH领域。Counterpoint Research数据显示，2025年下半年由ODM/IDH企业设计的智能手机出货量同比大幅下滑10%，结束了连续两年的增长态势。\", \"published\": \"2026-04-17 14:24:49  +0800\", \"title_detail\": {\"base\": \"https://36kr.com/feed\", \"type\": \"text/plain\", \"value\": \"机构：受存储价格大幅上涨冲击低端市场影响，2025年下半年ODM/IDH智能手机出货量同比下滑10%\", \"language\": null}, \"summary_detail\": {\"base\": \"https://36kr.com/feed\", \"type\": \"text/html\", \"value\": \"36氪获悉，据Counterpoint咨询，2025年下半年存储价格大幅上涨，给全球智能手机行业带来了显著的成本压力，尤其冲击了低端市场。2025年下半年售价150美元以下的智能手机销量同比下滑11%。由于OEM的中低端机型出货量高度依赖ODM/IDH，这场由成本上涨驱动的市场下行趋势不可避免地传导至ODM-IDH领域。Counterpoint Research数据显示，2025年下半年由ODM/IDH企业设计的智能手机出货量同比大幅下滑10%，结束了连续两年的增长态势。\", \"language\": null}, \"published_parsed\": [2026, 4, 17, 6, 24, 49, 4, 107, 0]}', '2026-04-17 15:07:51');
