INSERT INTO `article_storage` VALUES (16, 2264, '沪深两市成交额突破2万亿元', '{\"link\": \"https://36kr.com/newsflashes/3770512769532417?f=rss\", \"links\": [{\"rel\": \"alternate\", \"href\": \"https://36kr.com/newsflashes/3770512769532417?f=rss\", \"type\": \"text/html\"}], \"title\": \"沪深两市成交额突破2万亿元\", \"source\": {\"title\": \"36氪\"}, \"summary\": \"36氪获悉，沪深两市成交额突破2万亿元。\", \"published\": \"2026-04-17 14:03:56  +0800\", \"title_detail\": {\"base\": \"https://36kr.com/feed\", \"type\": \"text/plain\", \"value\": \"沪深两市成交额突破2万亿元\", \"language\": null}, \"summary_detail\": {\"base\": \"https://36kr.com/feed\", \"type\": \"text/html\", \"value\": \"36氪获悉，沪深两市成交额突破2万亿元。\", \"language\": null}, \"published_parsed\": [2026, 4, 17, 6, 3, 56, 4, 107, 0]}', '2026-04-17 15:07:55');
INSERT INTO `article_storage` VALUES (17, 2266, '特斯拉在台招聘工程师：要求具备先进制程芯片经验', '{\"link\": \"https://36kr.com/newsflashes/3770502592545285?f=rss\", \"links\": [{\"rel\": \"alternate\", \"href\": \"https://36kr.com/newsflashes/3770502592545285?f=rss\", \"type\": \"text/html\"}], \"title\": \"特斯拉在台招聘工程师：要求具备先进制程芯片经验\", \"source\": {\"title\": \"36氪\"}, \"summary\": \"据特斯拉网站上的招聘信息显示，该公司正在中国台湾地区招聘一批半导体工程师，以参与其“Terafab”人工智能芯片项目。特斯拉在台发布的工程岗位涵盖了多个核心的前端制造步骤，包括光刻、蚀刻、薄膜制作和化学机械抛光，以及良率工程和工艺集成。在职位要求中显示，有几项职位要求应聘者需要具备“在7纳米以下先进芯片制造节点以及2纳米级技术方面的经验”。目前，马斯克正在快马加鞭筹备Terafab半导体项目。知情人士透露，特斯拉的目标是在2029年开始芯片制造，然后逐步扩大规模。（财联社）\", \"published\": \"2026-04-17 13:53:34  +0800\", \"title_detail\": {\"base\": \"https://36kr.com/feed\", \"type\": \"text/plain\", \"value\": \"特斯拉在台招聘工程师：要求具备先进制程芯片经验\", \"language\": null}, \"summary_detail\": {\"base\": \"https://36kr.com/feed\", \"type\": \"text/html\", \"value\": \"据特斯拉网站上的招聘信息显示，该公司正在中国台湾地区招聘一批半导体工程师，以参与其“Terafab”人工智能芯片项目。特斯拉在台发布的工程岗位涵盖了多个核心的前端制造步骤，包括光刻、蚀刻、薄膜制作和化学机械抛光，以及良率工程和工艺集成。在职位要求中显示，有几项职位要求应聘者需要具备“在7纳米以下先进芯片制造节点以及2纳米级技术方面的经验”。目前，马斯克正在快马加鞭筹备Terafab半导体项目。知情人士透露，特斯拉的目标是在2029年开始芯片制造，然后逐步扩大规模。（财联社）\", \"language\": null}, \"published_parsed\": [2026, 4, 17, 5, 53, 34, 4, 107, 0]}', '2026-04-17 15:08:01');
INSERT INTO `article_storage` VALUES (18, 2269, '我国科学家找到了大脑皮层的起源', '{\"link\": \"https://36kr.com/newsflashes/3770501991449346?f=rss\", \"links\": [{\"rel\": \"alternate\", \"href\": \"https://36kr.com/newsflashes/3770501991449346?f=rss\", \"type\": \"text/html\"}], \"title\": \"我国科学家找到了大脑皮层的起源\", \"source\": {\"title\": \"36氪\"}, \"summary\": \"记者从中国科学院脑科学与智能技术卓越创新中心获悉，该中心刘赐融、孙怡迪研究组联合华大研究院等多家单位，通过研究首次揭示了灵长类大脑皮层双相反分子梯度组织规律，成功破解学界长期以来关于大脑皮层起源与扩张的学术争议。相关成果4月16日在国际学术期刊《科学》发表。（央视新闻）\", \"published\": \"2026-04-17 13:52:58  +0800\", \"title_detail\": {\"base\": \"https://36kr.com/feed\", \"type\": \"text/plain\", \"value\": \"我国科学家找到了大脑皮层的起源\", \"language\": null}, \"summary_detail\": {\"base\": \"https://36kr.com/feed\", \"type\": \"text/html\", \"value\": \"记者从中国科学院脑科学与智能技术卓越创新中心获悉，该中心刘赐融、孙怡迪研究组联合华大研究院等多家单位，通过研究首次揭示了灵长类大脑皮层双相反分子梯度组织规律，成功破解学界长期以来关于大脑皮层起源与扩张的学术争议。相关成果4月16日在国际学术期刊《科学》发表。（央视新闻）\", \"language\": null}, \"published_parsed\": [2026, 4, 17, 5, 52, 58, 4, 107, 0]}', '2026-04-17 15:08:03');
INSERT INTO `article_storage` VALUES (19, 2271, 'SpaceX最快或6月上市，谷歌或从SpaceX上市获巨额收益', '{\"link\": \"https://36kr.com/newsflashes/3770498285011719?f=rss\", \"links\": [{\"rel\": \"alternate\", \"href\": \"https://36kr.com/newsflashes/3770498285011719?f=rss\", \"type\": \"text/html\"}], \"title\": \"SpaceX最快或6月上市，谷歌或从SpaceX上市获巨额收益\", \"source\": {\"title\": \"36氪\"}, \"summary\": \"据美国媒体15日报道，美国太空探索技术公司、也就是SpaceX，近期在阿拉斯加州提交的监管文件显示，谷歌公司持有其6.11%的股份。SpaceX最早可能在今年6月挂牌上市，届时谷歌有望获得巨额收益。据悉，SpaceX已经提交首次公开募股申请，可能以1.75万亿至2万亿美元的估值进行IPO。如果按此估值计算，一旦SpaceX完成首次公开募股，谷歌的持股价值约为1069亿至1220亿美元。（央视财经）\", \"published\": \"2026-04-17 13:49:11  +0800\", \"title_detail\": {\"base\": \"https://36kr.com/feed\", \"type\": \"text/plain\", \"value\": \"SpaceX最快或6月上市，谷歌或从SpaceX上市获巨额收益\", \"language\": null}, \"summary_detail\": {\"base\": \"https://36kr.com/feed\", \"type\": \"text/html\", \"value\": \"据美国媒体15日报道，美国太空探索技术公司、也就是SpaceX，近期在阿拉斯加州提交的监管文件显示，谷歌公司持有其6.11%的股份。SpaceX最早可能在今年6月挂牌上市，届时谷歌有望获得巨额收益。据悉，SpaceX已经提交首次公开募股申请，可能以1.75万亿至2万亿美元的估值进行IPO。如果按此估值计算，一旦SpaceX完成首次公开募股，谷歌的持股价值约为1069亿至1220亿美元。（央视财经）\", \"language\": null}, \"published_parsed\": [2026, 4, 17, 5, 49, 11, 4, 107, 0]}', '2026-04-17 15:08:05');
INSERT INTO `article_storage` VALUES (20, 2274, '德意志银行预计美联储将在2026年维持利率不变', '{\"link\": \"https://36kr.com/newsflashes/3770489993052929?f=rss\", \"links\": [{\"rel\": \"alternate\", \"href\": \"https://36kr.com/newsflashes/3770489993052929?f=rss\", \"type\": \"text/html\"}], \"title\": \"德意志银行预计美联储将在2026年维持利率不变\", \"source\": {\"title\": \"36氪\"}, \"summary\": \"德意志银行预计美国联邦储备理事会（美联储/FED）将在2026年维持利率不变，理由是与中东战争相关的石油驱动的通胀风险、有韧性的经济增长以及劳动力市场紧张，这些因素都使得降息空间很小。该经纪公司此前预计美联储将在9月份降息。德意志银行的策略师在周四的一份报告中说，今年降息需要劳动力市场状况有所减弱，同时通胀走软。（新浪财经）\", \"published\": \"2026-04-17 13:40:45  +0800\", \"title_detail\": {\"base\": \"https://36kr.com/feed\", \"type\": \"text/plain\", \"value\": \"德意志银行预计美联储将在2026年维持利率不变\", \"language\": null}, \"summary_detail\": {\"base\": \"https://36kr.com/feed\", \"type\": \"text/html\", \"value\": \"德意志银行预计美国联邦储备理事会（美联储/FED）将在2026年维持利率不变，理由是与中东战争相关的石油驱动的通胀风险、有韧性的经济增长以及劳动力市场紧张，这些因素都使得降息空间很小。该经纪公司此前预计美联储将在9月份降息。德意志银行的策略师在周四的一份报告中说，今年降息需要劳动力市场状况有所减弱，同时通胀走软。（新浪财经）\", \"language\": null}, \"published_parsed\": [2026, 4, 17, 5, 40, 45, 4, 107, 0]}', '2026-04-17 15:08:11');
INSERT INTO `article_storage` VALUES (21, 2276, '零跑D19正式上市', '{\"link\": \"https://36kr.com/newsflashes/3770477774799360?f=rss\", \"links\": [{\"rel\": \"alternate\", \"href\": \"https://36kr.com/newsflashes/3770477774799360?f=rss\", \"type\": \"text/html\"}], \"title\": \"零跑D19正式上市\", \"source\": {\"title\": \"36氪\"}, \"summary\": \"36氪获悉，4月16日，零跑旗舰D平台首款车型——零跑D19正式上市，售价21.98-26.98万元。新车提供纯电、增程两种动力，以及六座、七座多种版本选择。\", \"published\": \"2026-04-17 13:28:20  +0800\", \"title_detail\": {\"base\": \"https://36kr.com/feed\", \"type\": \"text/plain\", \"value\": \"零跑D19正式上市\", \"language\": null}, \"summary_detail\": {\"base\": \"https://36kr.com/feed\", \"type\": \"text/html\", \"value\": \"36氪获悉，4月16日，零跑旗舰D平台首款车型——零跑D19正式上市，售价21.98-26.98万元。新车提供纯电、增程两种动力，以及六座、七座多种版本选择。\", \"language\": null}, \"published_parsed\": [2026, 4, 17, 5, 28, 20, 4, 107, 0]}', '2026-04-17 15:08:14');
INSERT INTO `article_storage` VALUES (22, 2279, '追觅科技受邀出席国家商务部中意企委会圆桌会，作为中方企业代表发言', '{\"link\": \"https://36kr.com/newsflashes/3770547590808320?f=rss\", \"links\": [{\"rel\": \"alternate\", \"href\": \"https://36kr.com/newsflashes/3770547590808320?f=rss\", \"type\": \"text/html\"}], \"title\": \"追觅科技受邀出席国家商务部中意企委会圆桌会，作为中方企业代表发言\", \"source\": {\"title\": \"36氪\"}, \"summary\": \"4月16日，由国家商务部主办的 “中意企业家委员会圆桌会”在北京举行。追觅科技受邀参会，并作为五家中方企业代表之一发言。追觅集团成立于2017年，目前已在高速数字马达领域做到全球行业第一，并在智能算法、仿生机械臂、全域智能芯片等方向形成系统化的核心技术壁垒。在意大利市场，追觅多次登顶亚马逊类目销量第一，并在意大利米兰开设两家旗舰店，并实现多个品类市占率第一。目前，追觅产品已进入全球120多个国家和地区，服务超4200万家庭。\", \"published\": \"2026-04-17 14:39:21  +0800\", \"title_detail\": {\"base\": \"https://36kr.com/feed\", \"type\": \"text/plain\", \"value\": \"追觅科技受邀出席国家商务部中意企委会圆桌会，作为中方企业代表发言\", \"language\": null}, \"summary_detail\": {\"base\": \"https://36kr.com/feed\", \"type\": \"text/html\", \"value\": \"4月16日，由国家商务部主办的 “中意企业家委员会圆桌会”在北京举行。追觅科技受邀参会，并作为五家中方企业代表之一发言。追觅集团成立于2017年，目前已在高速数字马达领域做到全球行业第一，并在智能算法、仿生机械臂、全域智能芯片等方向形成系统化的核心技术壁垒。在意大利市场，追觅多次登顶亚马逊类目销量第一，并在意大利米兰开设两家旗舰店，并实现多个品类市占率第一。目前，追觅产品已进入全球120多个国家和地区，服务超4200万家庭。\", \"language\": null}, \"published_parsed\": [2026, 4, 17, 6, 39, 21, 4, 107, 0]}', '2026-04-17 15:08:20');
INSERT INTO `article_storage` VALUES (23, 2280, '南向资金净买入额达60亿港元', '{\"link\": \"https://36kr.com/newsflashes/3770466618835462?f=rss\", \"links\": [{\"rel\": \"alternate\", \"href\": \"https://36kr.com/newsflashes/3770466618835462?f=rss\", \"type\": \"text/html\"}], \"title\": \"南向资金净买入额达60亿港元\", \"source\": {\"title\": \"36氪\"}, \"summary\": \"36氪获悉，南向资金净买入额达60亿港元。\", \"published\": \"2026-04-17 13:16:59  +0800\", \"title_detail\": {\"base\": \"https://36kr.com/feed\", \"type\": \"text/plain\", \"value\": \"南向资金净买入额达60亿港元\", \"language\": null}, \"summary_detail\": {\"base\": \"https://36kr.com/feed\", \"type\": \"text/html\", \"value\": \"36氪获悉，南向资金净买入额达60亿港元。\", \"language\": null}, \"published_parsed\": [2026, 4, 17, 5, 16, 59, 4, 107, 0]}', '2026-04-17 15:08:20');
INSERT INTO `article_storage` VALUES (24, 2281, '爱立信第一季度销售净额493.3亿瑞典克朗，不及预期', '{\"link\": \"https://36kr.com/newsflashes/3770457512788483?f=rss\", \"links\": [{\"rel\": \"alternate\", \"href\": \"https://36kr.com/newsflashes/3770457512788483?f=rss\", \"type\": \"text/html\"}], \"title\": \"爱立信第一季度销售净额493.3亿瑞典克朗，不及预期\", \"source\": {\"title\": \"36氪\"}, \"summary\": \"爱立信第一季度销售净额493.3亿瑞典克朗，预估510.4亿瑞典克朗；第一季度调整后EBIT 52.1亿瑞典克朗，预估55.5亿瑞典克朗；第一季度经调整毛利率48.1％，预估47.9％。（财联社）\", \"published\": \"2026-04-17 13:07:43  +0800\", \"title_detail\": {\"base\": \"https://36kr.com/feed\", \"type\": \"text/plain\", \"value\": \"爱立信第一季度销售净额493.3亿瑞典克朗，不及预期\", \"language\": null}, \"summary_detail\": {\"base\": \"https://36kr.com/feed\", \"type\": \"text/html\", \"value\": \"爱立信第一季度销售净额493.3亿瑞典克朗，预估510.4亿瑞典克朗；第一季度调整后EBIT 52.1亿瑞典克朗，预估55.5亿瑞典克朗；第一季度经调整毛利率48.1％，预估47.9％。（财联社）\", \"language\": null}, \"published_parsed\": [2026, 4, 17, 5, 7, 43, 4, 107, 0]}', '2026-04-17 15:08:22');
INSERT INTO `article_storage` VALUES (25, 2283, '8点1氪丨全季大连某酒店账号公开多名客人特殊订单备注；金立手机创始人被曝在印尼卖家具；雷军将连播15小时测试新SU7续航', '{\"link\": \"https://36kr.com/p/3770155029398018?f=rss\", \"links\": [{\"rel\": \"alternate\", \"href\": \"https://36kr.com/p/3770155029398018?f=rss\", \"type\": \"text/html\"}], \"title\": \"8点1氪丨全季大连某酒店账号公开多名客人特殊订单备注；金立手机创始人被曝在印尼卖家具；雷军将连播15小时测试新SU7续航\", \"source\": {\"title\": \"36氪\"}, \"summary\": \"<h2>今日热点导览</h2>\\n  <p>丝芭传媒：创始人王子杰去世，享年63岁</p>\\n  <p>国家统计局：日均词元调用量突破140万亿，较上年末增长40%</p>\\n  <p>京东发布机器人产业服务全景图</p>\\n  <p>为加速重塑Siri，苹果安排近200名工程师培训AI编程</p>\\n  <p>特朗普签发多项输油管道许可，以促进美加之间的石油运输</p>\\n  <h2>TOP3大新闻</h2>\\n  <p><strong>全季大连某酒店账号公开多名客人特殊订单备注，华住集团客服回应</strong></p>\\n  <p>近日，一则题为“全季客人备注大赏”的帖文在社交平台引发争议。涉事账号“全季大连xx酒店”将多名客人的特殊订单备注公开发布，配文称“每天被客人备注笑到捶桌”“前台已笑晕在系统里”。有网友发帖表示：“一个酒店官方账号，私自将客人订单备注发到网上，评论区引起网友无谓的猜测，有些甚至偏恶意。”</p>\\n  <p>针对此事，上游新闻记者4月16日致电涉事酒店。工作人员回应称，发布帖文的账号并非酒店官方账号，具体由谁开设他并不清楚。华住酒店集团客服表示，核查后发现，该账号确认为员工的个人账号，目前已要求该员工立即注销账号，并对其进行通报批评。（上游新闻）</p>\\n  <p><strong>消失8年后，金立创始人刘立荣被曝在印尼卖家具</strong></p>\\n  <p>据红星新闻4月16日报道，多位网友爆料称，刘立荣在印尼经营家具公司Starlead。去年7月，他曾身穿印尼当地传统服装，出席Starlead展厅开幕仪式，并在上台讲话后落座于该公司CEO身旁。而Starlead的创始人何星是刘立荣的老部下。Starlead公司官网显示，该公司成立于2023年9月，瞄准出海印尼的中国企业，致力于提供现代实用的家居家具，在印尼专卖店超过20家，海尔、宁德时代、小米等都是其客户。Starlead的创始人何星，是刘立荣的“老部下”。</p>\\n  <p>2017年，金立手机出货量同比减少了1000万台，远低于预期。同一年，有关刘立荣赌博输掉巨额资金的传闻开始在金立供应商之间流传。当时有接近金立公司股东的人士表示，董事长刘立荣在赌博上输了超过100亿，挪用公款的数目可能在60亿左右，不排除有人设局。刘立荣则在接受媒体采访时承认自己曾去塞班赌博，并表示懊悔，“赌这个东西真的不能沾，一失足成千古恨。不光是在于涉及多少钱，它会对你的品行定性，让一个人人格破产。”但他称自己没有输掉100亿，而是“十几亿”，其中不乏“借用”公司的钱。（红星新闻）</p>\\n  <p><strong>雷军将直播新SU7续航测试，从北京到上海大约15小时</strong></p>\\n  <p>4月16日，雷军发文称，去年年初他曾说过，“我开YU7标准版，充满电，从北京到上海，1300公里高速，中间只充了一次电，我非常震惊”。雷军表示，这次新SU7打算直播给大家看，他将于17日早上六点半开始，全程参加并直播从北京到上海的长途续航测试，大约十五小时。在评论区雷军回复网友称，自己已经紧张到好几天没睡好觉。他还回应网友对于黑稿的忧虑，表示“咋办呢？不能因为有黑稿，我们就不说话了？”雷军曾在直播中重谈“1300km只充一次电”话题，他表示短视频平台推送的片段很多时候是被水军剪辑的，为了给他贴上“虚假营销”的标签。（界面新闻）</p>\\n  <h2>大公司/大事件</h2>\\n  <p><strong>丝芭传媒：创始人王子杰去世，享年63岁</strong></p>\\n  <p>4月16日，上海丝芭文化传媒集团有限公司发布讣告：公司创始人王子杰，因突发心源性疾病，经抢救无效，于4月14日19时在上海逝世，享年63岁。（界面新闻）</p>\\n  <p><strong>杨利娟辞任特海CEO，接手海底捞红石榴计划</strong></p>\\n  <p>36氪获悉，4月15日，特海国际发布公告称，杨利娟已辞任公司执行董事兼CEO，并将加入海底捞国际控股有限公司，统筹推动“红石榴计划”实施。公开资料显示，海底捞于2024年8月启动“红石榴计划”，截至2025年底已推出20个餐饮品牌，共计207家餐厅。</p>\\n  <p><strong>小米18Pro新增AI按键，支持启动AI功能、控制智能家居及小米汽车</strong></p>\\n  <p>消息源“leo_hefeng”4月15日在X平台发布推文，分享了一组渲染图，展示了小米18Pro手机，重点凸显机身侧面的AI按键，支持启动AI功能、控制智能家居及小米汽车。</p>\\n  <p>外观方面，小米18Pro延续小米17Pro的三摄布局和后置副屏设计，值得关注的是侧边新增AI按钮。该按钮支持自定义功能，可在任意场景快速启动AI，同时控制智能家居设备，甚至兼容小米汽车。核心规格方面，小米18Pro预计配备6.3英寸显示屏，主摄与3倍长焦采用2亿像素组合，电池容量将突破7000mAh。（财经网科技）</p>\\n  <p><strong>国家统计局：日均词元调用量突破140万亿，较上年末增长40%</strong></p>\\n  <p>国家统计局副局长毛盛勇4月16日在国新办新闻发布会上表示，智能化发展的引领作用不断增强，中国人工智能商业化、规模化运营取得了阶段性突破。截至今年3月，日均词元（Token）调用量突破140万亿，比上年末增长超40%。人工智能发展赋能千行百业，带动相关领域快速增长。（证券时报）</p>\\n  <p><strong>算力涨价潮席卷全球：阿里、Anthropic连续调价，严重算力荒再现</strong></p>\\n  <p>算力涨价潮正在席卷全球，海内外巨头又开始了新一轮调价。阿里云四天连发三条产品涨价公告，调整百炼部分模型单元服务价格及DataWorks部分API免费额度。Anthropic调整了旗下企业级产品Claude Enterprise订阅模式，从每月每用户最高200美元的固定费用，转变为按照实际算力消耗收费，此外用户每月还需要固定缴纳20美元。中信证券指出，Token调用量井喷带来的是算力需求极大爆发，与此同时供给侧受到各类硬约束短期边际增量有限，目前国内外均出现了严重的算力荒。（财联社）</p>\\n  <p><strong>研究显示：大语言模型会在蒸馏中“夹带”自己的偏好</strong></p>\\n  <p>《自然》15日发表的一项研究显示，大语言模型（LLM）可能会将某些自己的偏好“夹带私货”传授给其他算法，即使在训练数据中清除原始特征后，这些本不需要的特征，仍可能持续存在。在一个案例中，一个模型似乎通过数据中的隐含信号，将自己对猫头鹰的偏好传递给了其他模型。该研究结果表明，在开发LLM时，需要进行更彻底的安全检查。（财联社）</p>\\n  <p><strong>京东发布机器人产业服务全景图</strong></p>\\n  <p>36氪获悉，4月15日，京东发布“机器人产业服务全景图”。全景图聚焦三大核心：携手超200家品牌，目标2026年销售破百亿；依托超级供应链，建全球最大具身数据采集中心、京东机器人售后维修服务3年覆盖50余城；基于JoyAI大模型加速开放JoyInside附身智能交互能力，为机器人注入“智慧大脑”。</p>\\n  <p><strong>电子布库存持续紧张，涨价周期尚未结束</strong></p>\\n  <p>从业内获悉，多家电子布（电子级玻璃纤维）厂商库存紧张，部分企业库存不足十天。行业整体扩产进度受织布机供应瓶颈制约，短期内补库难度较大。业内人士分析认为，在织布机瓶颈未突破、产能向高端布倾斜的背景下，电子布高景气格局仍将延续，涨价周期尚未结束。（上证报）</p>\\n  <p><strong>亚洲富豪挟250亿美元涌入AI领域，面对高估值毫无惧色</strong></p>\\n  <p>据报道，尽管对美国AI企业估值过高的疑虑渐起，亚洲富裕投资者仍向该领域投入数十亿美元的私人资本，毫无惧色。根据PitchBook数据显示，2025年亚洲高净值个人及家族办公室共向全球AI私募融资投入243亿美元。今年动能延续，截至4月8日，新增投资额已达9.5亿美元。这波投资热潮正值SpaceX、OpenAI和Anthropic PBC等行业巨头在募资中持续创下惊人估值。对亚洲富裕投资人而言，抓住世代级科技机会的吸引力，已超越潜在泡沫的风险。（新浪财经）</p>\\n  <p><strong>为加速重塑Siri，苹果安排近200名工程师培训AI编程</strong></p>\\n  <p>据报道，为了追赶AI竞争对手，苹果正在将近200名Siri工程师送往为期数周的训练营，学习如何使用AI进行编程，旨在提升程序员的AI编程能力。据悉，该培训覆盖了Siri团队近九成工程师。训练营的培训重点将是学习使用Anthropic旗下Claude Code等AI辅助开发工具。</p>\\n  <p>在此之前，Siri团队长期沿用传统开发模式，在AI辅助编程方面的应用相对滞后，这也导致近年来Siri的功能迭代速度放缓，与谷歌Assistant、亚马逊Alexa等竞品的差距逐渐拉大。谷歌Assistant深度集成Gemini模型，早已支持多步复合指令、跨应用协同；亚马逊Alexa拥有超10万种兼容智能家居设备，技能库丰富，擅长多设备联动控制。（界面新闻）</p>\\n  <p><strong>美联储4月维持利率不变的概率为98.4%</strong></p>\\n  <p>据CME“美联储观察”：美联储4月加息25个基点的概率为1.6%，维持利率不变的概率为98.4%。美联储到6月累计降息25个基点的概率为0%，维持利率不变的概率为98%，累计加息25个基点的概率为2%。（财联社）</p>\\n  <p><strong>特朗普签发多项输油管道许可，以促进美加之间的石油运输</strong></p>\\n  <p>据白宫公布的文件显示，美国总统特朗普15日签发了多项输油管道许可，其中包括一项新建输油管道的许可，旨在促进美国与加拿大之间的原油及油品运输。该建设许可已颁发给Bakken Pipeline Company，用于北达科他州伯克县的管道设施建设。此外，他还签发了其他许可，以维护和运营位于北达科他州和密西根州、靠近边境地区的现有输油管道。（新浪财经）</p>\\n  <p><strong>美股三大指数集体收涨，纳指十二连涨再创收盘新高</strong></p>\\n  <p>36氪获悉，4月16日收盘，美股三大指数集体上涨，纳指涨0.36%，为连续12个交易日上涨续创新高，标普500指数涨0.26%创历史新高，道指涨0.24%。大型科技股多数上涨，英特尔、甲骨文涨超5%，微软涨超2%，Meta、亚马逊、奈飞小幅上涨；苹果跌超1%，特斯拉、谷歌、英伟达小幅下跌。热门中概股多数走强，蔚来涨超6%，阿里巴巴、百度、小鹏集团涨超3%，理想汽车、拼多多涨超1%；老虎证券、小马智行跌超1%。</p>\\n  <p><strong>聚焦充电宝等重点领域，市场监管总局开展专项行动打击虚假CCC认证标志</strong></p>\\n  <p>市场监管总局在全国范围内部署开展CCC认证守底线专项行动，全链条、全方位加强CCC认证监管，营造安全放心的消费环境。强制性产品认证也就是我们常说的CCC认证制度是我国政府遵循世贸组织规则和国际通行规则建立的具有市场准入性质的合格评定体系，列入CCC认证目录的产品，需要获证后才能出厂、进口、销售。此次专项行动将突出一个“严”字。将对指定认证机构实施全覆盖监督检查，聚焦充电宝、电动自行车、燃气燃烧器具等重点领域，开展有效性抽查。深入推进CCC认证标志试点改革，精准打击虚假CCC认证标志，加强产品质量责任追溯。（界面新闻）</p>\\n  <p><strong>三星请求法院禁止工会开展非法罢工活动</strong></p>\\n  <p>一名发言人表示，三星电子于16日向法院提起申请，要求禁止其韩国工会在计划中的罢工期间开展非法活动。眼下这场薪资纠纷，恐将扰乱这家全球最大存储芯片制造商的生产运营。三星并未详细说明此次法律行动的具体细节。工会则将此举称为“宣战”，指责公司侵犯了受法律保护的罢工权。（新浪财经）</p>\\n  <p><strong>万科回应总裁空缺：已由董事长及高管团队分担相关职责</strong></p>\\n  <p>36氪获悉，万科A在深交所互动易平台回应了总裁职位空缺、泊寓业务、化债等市场关注。对总裁一职的空缺，万科表示，公司总裁职位目前处于空缺状态，公司已通过董事会授权及高管分工调整，由董事长及公司高管团队分担相关职责，确保了公司经营决策的正常开展和公司治理的有效运作。万科还提到，受多重因素影响，当前公司面临着多重风险挑战，整体经营形势依然十分严峻。在各方支持下，集团全力推进改革化险工作。</p>\\n  <p><strong>国际原油市场逐渐回归基本面定价，库存消耗继续推升油价</strong></p>\\n  <p>当前，国际原油市场从3月份“溢价绑架油价”的恐慌性交易，逐渐回归至基本面定价。最直观的数据表现为，纽约WTI近月期货合约升水较峰值回落约60%，国内原油期权波动率指数（VIX）自高点腰斩，同时原油期货沉淀资金规模降幅超四成。（证券时报）</p>\\n  <p><strong>摩根大通CEO杰米·戴蒙出售价值4000万美元摩根大通股票</strong></p>\\n  <p>摩根大通首席执行官杰米·戴蒙（Jamie Dimon）4月15日出售了价值超过4000万美元的该行股票，这是他最新一次减持套现。戴蒙执掌这家银行已超过20年，直到2023年底他才开始出售自己持有的该行股票，当时他卖出了100万股，价值约1.8亿美元。他去年出售了价值约2.33亿美元的股票，今年2月出售了价值约2100万美元的股票。他目前仍持有该行超过620万股股票，价值约19亿美元。这些股票由戴蒙、他的妻子和他的家族信托持有。（新浪财经）</p>\\n  <h2>上市进行时</h2>\\n  <p><strong>先正达</strong></p>\\n  <p>先正达寻求最早6月在香港以保密方式提交IPO申请。（财联社）</p>\\n  <p><strong>春光集团</strong></p>\\n  <p>36氪获悉，春光集团披露招股书，拟于近期在深市发行新股并上市。</p>\\n  <p><strong>中科宇航</strong></p>\\n  <p>36氪获悉，上交所官网显示，4月15日，商业火箭企业中科宇航IPO状态变为已问询。中科宇航成立于2018年，3月31日，该公司IPO申请获受理，后被抽中现场检查。此次IPO，中科宇航拟募资41.8亿元，其保荐机构为国泰海通证券。</p>\\n  <p><strong>华盛锂电</strong></p>\\n  <p>36氪获悉，华盛锂电公告，公司已于2026年4月15日向香港联交所递交了发行境外上市股份(H股)并在香港联交所主板上市的申请，并于同日在香港联交所网站刊登了本次发行上市的申请资料。本次发行上市事项的相关申请资料为公司按照香港证监会和香港联交所的要求编制和刊发，为草拟版本，且所载资料可能会适时作出更新及修订。</p>\\n  <h2>AI最前沿</h2>\\n  <p><strong>腾讯混元3D世界模型2.0发布并开源</strong></p>\\n  <p>36氪获悉，4月16日，混元3D世界模型2.0（HY-World 2.0）正式发布并开源。HY-World 2.0是一个多模态世界模型，能够根据文字、图片、视频等不同类型输入，自动生成、重建和模拟3D世界，同时支持多格式3D资产（Mesh/3DGS/点云等）导出，支持与现有的游戏工作流无缝对接，用于快速生成游戏地图和关卡原型。</p>\\n  <p><strong>OpenAI退出挪威“星门”数据中心合作，微软接手</strong></p>\\n  <p>OpenAI放弃直接从英国AI云服务商Nscale在挪威运营的数据中心租赁算力的计划。微软将接手该数据中心的剩余算力。OpenAI表示，正与微软洽谈从其手中租赁算力。（新浪财经）</p>\\n  <p><strong>Adobe推出可操作Claude的创意工具AI助手</strong></p>\\n  <p>Adobe4月15日宣布推出一款全新的人工智能助手，旨在帮助用户在其照片、视频及数字内容编辑软件套件中执行各项任务。该助手还将与Anthropic的Claude AI模型进行集成。（新浪财经）</p>\\n  <p><strong>马斯克的xAI据悉将向编程初创公司Cursor提供算力支持</strong></p>\\n  <p>据知情人士透露，埃隆·马斯克的人工智能公司xAI计划与编程初创公司Cursor达成一项新的合作协议，让后者利用其庞大的计算能力。消息人士称，Cursor计划在xAI的基础设施上训练其最新的AI编程模型Composer 2.5。他们还表示，Cursor将使用xAI的数万快图形处理器（GPU）。（新浪财经）</p>\\n  <p><strong>阶跃发布新一代语音生成模型StepAudio 2.5 TTS</strong></p>\\n  <p>36氪获悉，4月16日，阶跃发布新一代语音生成模型StepAudio 2.5 TTS。据介绍，该模型围绕全局语境控制、文中语境控制，以及零样本复刻与全音色控制等能力进行了升级，主要面向角色配音、有声内容创作、智能语音交互等场景。StepAudio 2.5 TTS支持利用自然语言来进行合成控制。目前，StepAudio 2.5 TTS已全量上线“阶跃星辰开放平台”和Step Plan。</p>\\n  <h2>大公司财报</h2>\\n  <p><strong>台积电：预计第二季度毛利率65.5％-67.5％</strong></p>\\n  <p>台积电预计第二季度毛利率65.5％-67.5％，市场预估64.1％；预计第二季度销售额390亿美元-402亿美元，预估381.1亿美元。（财联社）</p>\\n  <p><strong>永辉超市：一季度净利润2.87亿元，同比增长94.40%</strong></p>\\n  <p>36氪获悉，永辉超市发布2026年第一季度业绩报告。报告显示，一季度营业收入133.67亿元，同比减少23.53%；净利润2.87亿元，同比增长94.40%；扣非后归母净利润为2.47亿元，同比增长79.55%。此外，截至一季度末，永辉超市全国累计调改门店达327家。</p>\\n  <p><strong>贵州茅台：2025年实现营业收入1688.38亿元，同比下降1.21%</strong></p>\\n  <p>36氪获悉，贵州茅台发布2025年业绩报告。报告显示，2025年实现营业收入1688.38亿元，同比下降1.21%；归属于上市公司股东的净利润为823.20亿元，同比下降4.53%。拟向全体股东每股派发现金红利27.993元（含税）。</p>\\n  <p><strong>太平鸟：2025年净利润1.74亿元，同比下降32.57%</strong></p>\\n  <p>36氪获悉，太平鸟发布2025年业绩报告。报告显示，2025年营业收入63.34亿元，同比下降6.88%。净利润1.74亿元，同比下降32.57%。公司拟每10股派发现金红利3元（含税），拟派发现金红利1.41亿元，剩余未分配利润结转以后年度分配。2026年第一季度营收为16.56亿元，同比下降0.75%：净利润为1.37亿元，同比增长10.3%。</p>\\n  <p><strong>华友钴业：2026年第一季度净利润24.97亿元，同比增长99.45%</strong></p>\\n  <p>36氪获悉，华友钴业发布2026年第一季度业绩报告。报告显示，一季度实现营业收入258.04亿元，同比增长44.62%；归属于上市公司股东的净利润为24.97亿元，同比增长99.45%。业绩变动主要系产品销量增加及金属价格回升所致，以及主要受益于镍、钴、锂等金属价格的回升及公司产业一体化经营优势的持续释放。</p>\\n  <h2>投融资</h2>\\n  <p><strong>“它石智航”完成超4.5亿美金Pre-A轮融资</strong></p>\\n  <p>4月16日，“它石智航”宣布完成超4.5亿美金Pre-A轮融资，创下中国具身智能有史以来最高单轮融资纪录，由高瓴创投，与红杉中国联合领投，美团龙珠、中金资本、凯联资本、东方富海、钧山投资等财务基金跟投。本轮融资将用于加速打造通用具身大模型AWE和持续吸引行业人才，下一轮融资将重点用于打造真干活、真量产的机器人。</p>\\n  <h2>酷产品</h2>\\n  <p><strong>宝马将在北京车展推出M3 40周年限量版</strong></p>\\n  <p>36氪获悉，宝马将在北京国际车展推出M3 40周年限量版车型，涵盖轿车与旅行车两种版本，在华各限量20台，于2026年下半年上市。</p>\\n  <p><strong>奥迪高管透露明年将推第三款中国专属车型</strong></p>\\n  <p>据报道，德国奥迪汽车公司首席执行官索内拉表示，为重夺中国市场份额，奥迪计划于明年与中国合作伙伴上汽集团联合推出第三款中国专属车型，定位为高端运动型轿车。索内拉强调，该车型已进入开发阶段，并延续“中国需求优先”策略。（界面新闻）</p>\\n  <p><strong>追觅科技旗下AI视觉机器人品牌NAVO亮相广交会</strong></p>\\n  <p>36氪获悉，4月15日，第139届中国进出口商品交易会（即2026春季广交会）在广州开幕，追觅科技旗下AI视觉机器人品牌NAVO，携全系列高端AI智能摄像头产品亮相。据了解，NAVO自研专属安防芯片架构，搭配黑光全彩夜视引擎，首创事件级AI平台AlgoMart。上市半年，订单销售额超过6000万。</p>\\n  <h2>AI图谱</h2>\\n  <p><strong>AI图谱，带你解读最新最快的AI咨询。46小时内两次袭击，美国人这么怕AI？</strong></p>\\n  <p><strong>整理</strong>｜Kris&nbsp;</p>\", \"published\": \"2026-04-17 08:02:44  +0800\", \"title_detail\": {\"base\": \"https://36kr.com/feed\", \"type\": \"text/plain\", \"value\": \"8点1氪丨全季大连某酒店账号公开多名客人特殊订单备注；金立手机创始人被曝在印尼卖家具；雷军将连播15小时测试新SU7续航\", \"language\": null}, \"summary_detail\": {\"base\": \"https://36kr.com/feed\", \"type\": \"text/html\", \"value\": \"<h2>今日热点导览</h2>\\n  <p>丝芭传媒：创始人王子杰去世，享年63岁</p>\\n  <p>国家统计局：日均词元调用量突破140万亿，较上年末增长40%</p>\\n  <p>京东发布机器人产业服务全景图</p>\\n  <p>为加速重塑Siri，苹果安排近200名工程师培训AI编程</p>\\n  <p>特朗普签发多项输油管道许可，以促进美加之间的石油运输</p>\\n  <h2>TOP3大新闻</h2>\\n  <p><strong>全季大连某酒店账号公开多名客人特殊订单备注，华住集团客服回应</strong></p>\\n  <p>近日，一则题为“全季客人备注大赏”的帖文在社交平台引发争议。涉事账号“全季大连xx酒店”将多名客人的特殊订单备注公开发布，配文称“每天被客人备注笑到捶桌”“前台已笑晕在系统里”。有网友发帖表示：“一个酒店官方账号，私自将客人订单备注发到网上，评论区引起网友无谓的猜测，有些甚至偏恶意。”</p>\\n  <p>针对此事，上游新闻记者4月16日致电涉事酒店。工作人员回应称，发布帖文的账号并非酒店官方账号，具体由谁开设他并不清楚。华住酒店集团客服表示，核查后发现，该账号确认为员工的个人账号，目前已要求该员工立即注销账号，并对其进行通报批评。（上游新闻）</p>\\n  <p><strong>消失8年后，金立创始人刘立荣被曝在印尼卖家具</strong></p>\\n  <p>据红星新闻4月16日报道，多位网友爆料称，刘立荣在印尼经营家具公司Starlead。去年7月，他曾身穿印尼当地传统服装，出席Starlead展厅开幕仪式，并在上台讲话后落座于该公司CEO身旁。而Starlead的创始人何星是刘立荣的老部下。Starlead公司官网显示，该公司成立于2023年9月，瞄准出海印尼的中国企业，致力于提供现代实用的家居家具，在印尼专卖店超过20家，海尔、宁德时代、小米等都是其客户。Starlead的创始人何星，是刘立荣的“老部下”。</p>\\n  <p>2017年，金立手机出货量同比减少了1000万台，远低于预期。同一年，有关刘立荣赌博输掉巨额资金的传闻开始在金立供应商之间流传。当时有接近金立公司股东的人士表示，董事长刘立荣在赌博上输了超过100亿，挪用公款的数目可能在60亿左右，不排除有人设局。刘立荣则在接受媒体采访时承认自己曾去塞班赌博，并表示懊悔，“赌这个东西真的不能沾，一失足成千古恨。不光是在于涉及多少钱，它会对你的品行定性，让一个人人格破产。”但他称自己没有输掉100亿，而是“十几亿”，其中不乏“借用”公司的钱。（红星新闻）</p>\\n  <p><strong>雷军将直播新SU7续航测试，从北京到上海大约15小时</strong></p>\\n  <p>4月16日，雷军发文称，去年年初他曾说过，“我开YU7标准版，充满电，从北京到上海，1300公里高速，中间只充了一次电，我非常震惊”。雷军表示，这次新SU7打算直播给大家看，他将于17日早上六点半开始，全程参加并直播从北京到上海的长途续航测试，大约十五小时。在评论区雷军回复网友称，自己已经紧张到好几天没睡好觉。他还回应网友对于黑稿的忧虑，表示“咋办呢？不能因为有黑稿，我们就不说话了？”雷军曾在直播中重谈“1300km只充一次电”话题，他表示短视频平台推送的片段很多时候是被水军剪辑的，为了给他贴上“虚假营销”的标签。（界面新闻）</p>\\n  <h2>大公司/大事件</h2>\\n  <p><strong>丝芭传媒：创始人王子杰去世，享年63岁</strong></p>\\n  <p>4月16日，上海丝芭文化传媒集团有限公司发布讣告：公司创始人王子杰，因突发心源性疾病，经抢救无效，于4月14日19时在上海逝世，享年63岁。（界面新闻）</p>\\n  <p><strong>杨利娟辞任特海CEO，接手海底捞红石榴计划</strong></p>\\n  <p>36氪获悉，4月15日，特海国际发布公告称，杨利娟已辞任公司执行董事兼CEO，并将加入海底捞国际控股有限公司，统筹推动“红石榴计划”实施。公开资料显示，海底捞于2024年8月启动“红石榴计划”，截至2025年底已推出20个餐饮品牌，共计207家餐厅。</p>\\n  <p><strong>小米18Pro新增AI按键，支持启动AI功能、控制智能家居及小米汽车</strong></p>\\n  <p>消息源“leo_hefeng”4月15日在X平台发布推文，分享了一组渲染图，展示了小米18Pro手机，重点凸显机身侧面的AI按键，支持启动AI功能、控制智能家居及小米汽车。</p>\\n  <p>外观方面，小米18Pro延续小米17Pro的三摄布局和后置副屏设计，值得关注的是侧边新增AI按钮。该按钮支持自定义功能，可在任意场景快速启动AI，同时控制智能家居设备，甚至兼容小米汽车。核心规格方面，小米18Pro预计配备6.3英寸显示屏，主摄与3倍长焦采用2亿像素组合，电池容量将突破7000mAh。（财经网科技）</p>\\n  <p><strong>国家统计局：日均词元调用量突破140万亿，较上年末增长40%</strong></p>\\n  <p>国家统计局副局长毛盛勇4月16日在国新办新闻发布会上表示，智能化发展的引领作用不断增强，中国人工智能商业化、规模化运营取得了阶段性突破。截至今年3月，日均词元（Token）调用量突破140万亿，比上年末增长超40%。人工智能发展赋能千行百业，带动相关领域快速增长。（证券时报）</p>\\n  <p><strong>算力涨价潮席卷全球：阿里、Anthropic连续调价，严重算力荒再现</strong></p>\\n  <p>算力涨价潮正在席卷全球，海内外巨头又开始了新一轮调价。阿里云四天连发三条产品涨价公告，调整百炼部分模型单元服务价格及DataWorks部分API免费额度。Anthropic调整了旗下企业级产品Claude Enterprise订阅模式，从每月每用户最高200美元的固定费用，转变为按照实际算力消耗收费，此外用户每月还需要固定缴纳20美元。中信证券指出，Token调用量井喷带来的是算力需求极大爆发，与此同时供给侧受到各类硬约束短期边际增量有限，目前国内外均出现了严重的算力荒。（财联社）</p>\\n  <p><strong>研究显示：大语言模型会在蒸馏中“夹带”自己的偏好</strong></p>\\n  <p>《自然》15日发表的一项研究显示，大语言模型（LLM）可能会将某些自己的偏好“夹带私货”传授给其他算法，即使在训练数据中清除原始特征后，这些本不需要的特征，仍可能持续存在。在一个案例中，一个模型似乎通过数据中的隐含信号，将自己对猫头鹰的偏好传递给了其他模型。该研究结果表明，在开发LLM时，需要进行更彻底的安全检查。（财联社）</p>\\n  <p><strong>京东发布机器人产业服务全景图</strong></p>\\n  <p>36氪获悉，4月15日，京东发布“机器人产业服务全景图”。全景图聚焦三大核心：携手超200家品牌，目标2026年销售破百亿；依托超级供应链，建全球最大具身数据采集中心、京东机器人售后维修服务3年覆盖50余城；基于JoyAI大模型加速开放JoyInside附身智能交互能力，为机器人注入“智慧大脑”。</p>\\n  <p><strong>电子布库存持续紧张，涨价周期尚未结束</strong></p>\\n  <p>从业内获悉，多家电子布（电子级玻璃纤维）厂商库存紧张，部分企业库存不足十天。行业整体扩产进度受织布机供应瓶颈制约，短期内补库难度较大。业内人士分析认为，在织布机瓶颈未突破、产能向高端布倾斜的背景下，电子布高景气格局仍将延续，涨价周期尚未结束。（上证报）</p>\\n  <p><strong>亚洲富豪挟250亿美元涌入AI领域，面对高估值毫无惧色</strong></p>\\n  <p>据报道，尽管对美国AI企业估值过高的疑虑渐起，亚洲富裕投资者仍向该领域投入数十亿美元的私人资本，毫无惧色。根据PitchBook数据显示，2025年亚洲高净值个人及家族办公室共向全球AI私募融资投入243亿美元。今年动能延续，截至4月8日，新增投资额已达9.5亿美元。这波投资热潮正值SpaceX、OpenAI和Anthropic PBC等行业巨头在募资中持续创下惊人估值。对亚洲富裕投资人而言，抓住世代级科技机会的吸引力，已超越潜在泡沫的风险。（新浪财经）</p>\\n  <p><strong>为加速重塑Siri，苹果安排近200名工程师培训AI编程</strong></p>\\n  <p>据报道，为了追赶AI竞争对手，苹果正在将近200名Siri工程师送往为期数周的训练营，学习如何使用AI进行编程，旨在提升程序员的AI编程能力。据悉，该培训覆盖了Siri团队近九成工程师。训练营的培训重点将是学习使用Anthropic旗下Claude Code等AI辅助开发工具。</p>\\n  <p>在此之前，Siri团队长期沿用传统开发模式，在AI辅助编程方面的应用相对滞后，这也导致近年来Siri的功能迭代速度放缓，与谷歌Assistant、亚马逊Alexa等竞品的差距逐渐拉大。谷歌Assistant深度集成Gemini模型，早已支持多步复合指令、跨应用协同；亚马逊Alexa拥有超10万种兼容智能家居设备，技能库丰富，擅长多设备联动控制。（界面新闻）</p>\\n  <p><strong>美联储4月维持利率不变的概率为98.4%</strong></p>\\n  <p>据CME“美联储观察”：美联储4月加息25个基点的概率为1.6%，维持利率不变的概率为98.4%。美联储到6月累计降息25个基点的概率为0%，维持利率不变的概率为98%，累计加息25个基点的概率为2%。（财联社）</p>\\n  <p><strong>特朗普签发多项输油管道许可，以促进美加之间的石油运输</strong></p>\\n  <p>据白宫公布的文件显示，美国总统特朗普15日签发了多项输油管道许可，其中包括一项新建输油管道的许可，旨在促进美国与加拿大之间的原油及油品运输。该建设许可已颁发给Bakken Pipeline Company，用于北达科他州伯克县的管道设施建设。此外，他还签发了其他许可，以维护和运营位于北达科他州和密西根州、靠近边境地区的现有输油管道。（新浪财经）</p>\\n  <p><strong>美股三大指数集体收涨，纳指十二连涨再创收盘新高</strong></p>\\n  <p>36氪获悉，4月16日收盘，美股三大指数集体上涨，纳指涨0.36%，为连续12个交易日上涨续创新高，标普500指数涨0.26%创历史新高，道指涨0.24%。大型科技股多数上涨，英特尔、甲骨文涨超5%，微软涨超2%，Meta、亚马逊、奈飞小幅上涨；苹果跌超1%，特斯拉、谷歌、英伟达小幅下跌。热门中概股多数走强，蔚来涨超6%，阿里巴巴、百度、小鹏集团涨超3%，理想汽车、拼多多涨超1%；老虎证券、小马智行跌超1%。</p>\\n  <p><strong>聚焦充电宝等重点领域，市场监管总局开展专项行动打击虚假CCC认证标志</strong></p>\\n  <p>市场监管总局在全国范围内部署开展CCC认证守底线专项行动，全链条、全方位加强CCC认证监管，营造安全放心的消费环境。强制性产品认证也就是我们常说的CCC认证制度是我国政府遵循世贸组织规则和国际通行规则建立的具有市场准入性质的合格评定体系，列入CCC认证目录的产品，需要获证后才能出厂、进口、销售。此次专项行动将突出一个“严”字。将对指定认证机构实施全覆盖监督检查，聚焦充电宝、电动自行车、燃气燃烧器具等重点领域，开展有效性抽查。深入推进CCC认证标志试点改革，精准打击虚假CCC认证标志，加强产品质量责任追溯。（界面新闻）</p>\\n  <p><strong>三星请求法院禁止工会开展非法罢工活动</strong></p>\\n  <p>一名发言人表示，三星电子于16日向法院提起申请，要求禁止其韩国工会在计划中的罢工期间开展非法活动。眼下这场薪资纠纷，恐将扰乱这家全球最大存储芯片制造商的生产运营。三星并未详细说明此次法律行动的具体细节。工会则将此举称为“宣战”，指责公司侵犯了受法律保护的罢工权。（新浪财经）</p>\\n  <p><strong>万科回应总裁空缺：已由董事长及高管团队分担相关职责</strong></p>\\n  <p>36氪获悉，万科A在深交所互动易平台回应了总裁职位空缺、泊寓业务、化债等市场关注。对总裁一职的空缺，万科表示，公司总裁职位目前处于空缺状态，公司已通过董事会授权及高管分工调整，由董事长及公司高管团队分担相关职责，确保了公司经营决策的正常开展和公司治理的有效运作。万科还提到，受多重因素影响，当前公司面临着多重风险挑战，整体经营形势依然十分严峻。在各方支持下，集团全力推进改革化险工作。</p>\\n  <p><strong>国际原油市场逐渐回归基本面定价，库存消耗继续推升油价</strong></p>\\n  <p>当前，国际原油市场从3月份“溢价绑架油价”的恐慌性交易，逐渐回归至基本面定价。最直观的数据表现为，纽约WTI近月期货合约升水较峰值回落约60%，国内原油期权波动率指数（VIX）自高点腰斩，同时原油期货沉淀资金规模降幅超四成。（证券时报）</p>\\n  <p><strong>摩根大通CEO杰米·戴蒙出售价值4000万美元摩根大通股票</strong></p>\\n  <p>摩根大通首席执行官杰米·戴蒙（Jamie Dimon）4月15日出售了价值超过4000万美元的该行股票，这是他最新一次减持套现。戴蒙执掌这家银行已超过20年，直到2023年底他才开始出售自己持有的该行股票，当时他卖出了100万股，价值约1.8亿美元。他去年出售了价值约2.33亿美元的股票，今年2月出售了价值约2100万美元的股票。他目前仍持有该行超过620万股股票，价值约19亿美元。这些股票由戴蒙、他的妻子和他的家族信托持有。（新浪财经）</p>\\n  <h2>上市进行时</h2>\\n  <p><strong>先正达</strong></p>\\n  <p>先正达寻求最早6月在香港以保密方式提交IPO申请。（财联社）</p>\\n  <p><strong>春光集团</strong></p>\\n  <p>36氪获悉，春光集团披露招股书，拟于近期在深市发行新股并上市。</p>\\n  <p><strong>中科宇航</strong></p>\\n  <p>36氪获悉，上交所官网显示，4月15日，商业火箭企业中科宇航IPO状态变为已问询。中科宇航成立于2018年，3月31日，该公司IPO申请获受理，后被抽中现场检查。此次IPO，中科宇航拟募资41.8亿元，其保荐机构为国泰海通证券。</p>\\n  <p><strong>华盛锂电</strong></p>\\n  <p>36氪获悉，华盛锂电公告，公司已于2026年4月15日向香港联交所递交了发行境外上市股份(H股)并在香港联交所主板上市的申请，并于同日在香港联交所网站刊登了本次发行上市的申请资料。本次发行上市事项的相关申请资料为公司按照香港证监会和香港联交所的要求编制和刊发，为草拟版本，且所载资料可能会适时作出更新及修订。</p>\\n  <h2>AI最前沿</h2>\\n  <p><strong>腾讯混元3D世界模型2.0发布并开源</strong></p>\\n  <p>36氪获悉，4月16日，混元3D世界模型2.0（HY-World 2.0）正式发布并开源。HY-World 2.0是一个多模态世界模型，能够根据文字、图片、视频等不同类型输入，自动生成、重建和模拟3D世界，同时支持多格式3D资产（Mesh/3DGS/点云等）导出，支持与现有的游戏工作流无缝对接，用于快速生成游戏地图和关卡原型。</p>\\n  <p><strong>OpenAI退出挪威“星门”数据中心合作，微软接手</strong></p>\\n  <p>OpenAI放弃直接从英国AI云服务商Nscale在挪威运营的数据中心租赁算力的计划。微软将接手该数据中心的剩余算力。OpenAI表示，正与微软洽谈从其手中租赁算力。（新浪财经）</p>\\n  <p><strong>Adobe推出可操作Claude的创意工具AI助手</strong></p>\\n  <p>Adobe4月15日宣布推出一款全新的人工智能助手，旨在帮助用户在其照片、视频及数字内容编辑软件套件中执行各项任务。该助手还将与Anthropic的Claude AI模型进行集成。（新浪财经）</p>\\n  <p><strong>马斯克的xAI据悉将向编程初创公司Cursor提供算力支持</strong></p>\\n  <p>据知情人士透露，埃隆·马斯克的人工智能公司xAI计划与编程初创公司Cursor达成一项新的合作协议，让后者利用其庞大的计算能力。消息人士称，Cursor计划在xAI的基础设施上训练其最新的AI编程模型Composer 2.5。他们还表示，Cursor将使用xAI的数万快图形处理器（GPU）。（新浪财经）</p>\\n  <p><strong>阶跃发布新一代语音生成模型StepAudio 2.5 TTS</strong></p>\\n  <p>36氪获悉，4月16日，阶跃发布新一代语音生成模型StepAudio 2.5 TTS。据介绍，该模型围绕全局语境控制、文中语境控制，以及零样本复刻与全音色控制等能力进行了升级，主要面向角色配音、有声内容创作、智能语音交互等场景。StepAudio 2.5 TTS支持利用自然语言来进行合成控制。目前，StepAudio 2.5 TTS已全量上线“阶跃星辰开放平台”和Step Plan。</p>\\n  <h2>大公司财报</h2>\\n  <p><strong>台积电：预计第二季度毛利率65.5％-67.5％</strong></p>\\n  <p>台积电预计第二季度毛利率65.5％-67.5％，市场预估64.1％；预计第二季度销售额390亿美元-402亿美元，预估381.1亿美元。（财联社）</p>\\n  <p><strong>永辉超市：一季度净利润2.87亿元，同比增长94.40%</strong></p>\\n  <p>36氪获悉，永辉超市发布2026年第一季度业绩报告。报告显示，一季度营业收入133.67亿元，同比减少23.53%；净利润2.87亿元，同比增长94.40%；扣非后归母净利润为2.47亿元，同比增长79.55%。此外，截至一季度末，永辉超市全国累计调改门店达327家。</p>\\n  <p><strong>贵州茅台：2025年实现营业收入1688.38亿元，同比下降1.21%</strong></p>\\n  <p>36氪获悉，贵州茅台发布2025年业绩报告。报告显示，2025年实现营业收入1688.38亿元，同比下降1.21%；归属于上市公司股东的净利润为823.20亿元，同比下降4.53%。拟向全体股东每股派发现金红利27.993元（含税）。</p>\\n  <p><strong>太平鸟：2025年净利润1.74亿元，同比下降32.57%</strong></p>\\n  <p>36氪获悉，太平鸟发布2025年业绩报告。报告显示，2025年营业收入63.34亿元，同比下降6.88%。净利润1.74亿元，同比下降32.57%。公司拟每10股派发现金红利3元（含税），拟派发现金红利1.41亿元，剩余未分配利润结转以后年度分配。2026年第一季度营收为16.56亿元，同比下降0.75%：净利润为1.37亿元，同比增长10.3%。</p>\\n  <p><strong>华友钴业：2026年第一季度净利润24.97亿元，同比增长99.45%</strong></p>\\n  <p>36氪获悉，华友钴业发布2026年第一季度业绩报告。报告显示，一季度实现营业收入258.04亿元，同比增长44.62%；归属于上市公司股东的净利润为24.97亿元，同比增长99.45%。业绩变动主要系产品销量增加及金属价格回升所致，以及主要受益于镍、钴、锂等金属价格的回升及公司产业一体化经营优势的持续释放。</p>\\n  <h2>投融资</h2>\\n  <p><strong>“它石智航”完成超4.5亿美金Pre-A轮融资</strong></p>\\n  <p>4月16日，“它石智航”宣布完成超4.5亿美金Pre-A轮融资，创下中国具身智能有史以来最高单轮融资纪录，由高瓴创投，与红杉中国联合领投，美团龙珠、中金资本、凯联资本、东方富海、钧山投资等财务基金跟投。本轮融资将用于加速打造通用具身大模型AWE和持续吸引行业人才，下一轮融资将重点用于打造真干活、真量产的机器人。</p>\\n  <h2>酷产品</h2>\\n  <p><strong>宝马将在北京车展推出M3 40周年限量版</strong></p>\\n  <p>36氪获悉，宝马将在北京国际车展推出M3 40周年限量版车型，涵盖轿车与旅行车两种版本，在华各限量20台，于2026年下半年上市。</p>\\n  <p><strong>奥迪高管透露明年将推第三款中国专属车型</strong></p>\\n  <p>据报道，德国奥迪汽车公司首席执行官索内拉表示，为重夺中国市场份额，奥迪计划于明年与中国合作伙伴上汽集团联合推出第三款中国专属车型，定位为高端运动型轿车。索内拉强调，该车型已进入开发阶段，并延续“中国需求优先”策略。（界面新闻）</p>\\n  <p><strong>追觅科技旗下AI视觉机器人品牌NAVO亮相广交会</strong></p>\\n  <p>36氪获悉，4月15日，第139届中国进出口商品交易会（即2026春季广交会）在广州开幕，追觅科技旗下AI视觉机器人品牌NAVO，携全系列高端AI智能摄像头产品亮相。据了解，NAVO自研专属安防芯片架构，搭配黑光全彩夜视引擎，首创事件级AI平台AlgoMart。上市半年，订单销售额超过6000万。</p>\\n  <h2>AI图谱</h2>\\n  <p><strong>AI图谱，带你解读最新最快的AI咨询。46小时内两次袭击，美国人这么怕AI？</strong></p>\\n  <p><strong>整理</strong>｜Kris&nbsp;</p>\", \"language\": null}, \"published_parsed\": [2026, 4, 17, 0, 2, 44, 4, 107, 0]}', '2026-04-17 15:08:24');
INSERT INTO `article_storage` VALUES (26, 2284, '长鑫存储、长江存储现“先款排产”', '{\"link\": \"https://36kr.com/newsflashes/3770451858965251?f=rss\", \"links\": [{\"rel\": \"alternate\", \"href\": \"https://36kr.com/newsflashes/3770451858965251?f=rss\", \"type\": \"text/html\"}], \"title\": \"长鑫存储、长江存储现“先款排产”\", \"source\": {\"title\": \"36氪\"}, \"summary\": \"从产业链获悉，自去年四季度起，长鑫存储与长江存储已出现“抢货”现象，目前仍在持续。具体来看，下游客户需先向渠道商打款，资金到账后由渠道商排队进入排产体系，待有货后再通知提货。产业链人士表示，上述变化与本轮存储芯片价格上行节奏基本同步。（界面）\", \"published\": \"2026-04-17 13:01:58  +0800\", \"title_detail\": {\"base\": \"https://36kr.com/feed\", \"type\": \"text/plain\", \"value\": \"长鑫存储、长江存储现“先款排产”\", \"language\": null}, \"summary_detail\": {\"base\": \"https://36kr.com/feed\", \"type\": \"text/html\", \"value\": \"从产业链获悉，自去年四季度起，长鑫存储与长江存储已出现“抢货”现象，目前仍在持续。具体来看，下游客户需先向渠道商打款，资金到账后由渠道商排队进入排产体系，待有货后再通知提货。产业链人士表示，上述变化与本轮存储芯片价格上行节奏基本同步。（界面）\", \"language\": null}, \"published_parsed\": [2026, 4, 17, 5, 1, 58, 4, 107, 0]}', '2026-04-17 15:08:26');
INSERT INTO `article_storage` VALUES (27, 2286, '通义千问关联公司增资至2亿元', '{\"link\": \"https://36kr.com/newsflashes/3770417832346116?f=rss\", \"links\": [{\"rel\": \"alternate\", \"href\": \"https://36kr.com/newsflashes/3770417832346116?f=rss\", \"type\": \"text/html\"}], \"title\": \"通义千问关联公司增资至2亿元\", \"source\": {\"title\": \"36氪\"}, \"summary\": \"36氪获悉，爱企查App显示，近日，通义千问关联公司通义云启（杭州）信息技术有限公司发生工商变更，新增杭州通义实验室科技有限公司为股东，同时，注册资本由1亿元人民币增至2亿元人民币，增幅100%。 该公司成立于2018年11月，法定代表人为于文渊，经营范围包括广告制作、计算机软硬件及辅助设备批发、电子产品销售等，现由阿里云计算有限公司及上述新增股东共同持股。\", \"published\": \"2026-04-17 12:50:14  +0800\", \"title_detail\": {\"base\": \"https://36kr.com/feed\", \"type\": \"text/plain\", \"value\": \"通义千问关联公司增资至2亿元\", \"language\": null}, \"summary_detail\": {\"base\": \"https://36kr.com/feed\", \"type\": \"text/html\", \"value\": \"36氪获悉，爱企查App显示，近日，通义千问关联公司通义云启（杭州）信息技术有限公司发生工商变更，新增杭州通义实验室科技有限公司为股东，同时，注册资本由1亿元人民币增至2亿元人民币，增幅100%。 该公司成立于2018年11月，法定代表人为于文渊，经营范围包括广告制作、计算机软硬件及辅助设备批发、电子产品销售等，现由阿里云计算有限公司及上述新增股东共同持股。\", \"language\": null}, \"published_parsed\": [2026, 4, 17, 4, 50, 14, 4, 107, 0]}', '2026-04-17 15:08:33');
INSERT INTO `article_storage` VALUES (28, 2287, '现货白银日内涨超1%', '{\"link\": \"https://36kr.com/newsflashes/3770436976001801?f=rss\", \"links\": [{\"rel\": \"alternate\", \"href\": \"https://36kr.com/newsflashes/3770436976001801?f=rss\", \"type\": \"text/html\"}], \"title\": \"现货白银日内涨超1%\", \"source\": {\"title\": \"36氪\"}, \"summary\": \"36氪获悉，现货白银日内涨超1%，现报79.20美元/盎司。\", \"published\": \"2026-04-17 12:46:49  +0800\", \"title_detail\": {\"base\": \"https://36kr.com/feed\", \"type\": \"text/plain\", \"value\": \"现货白银日内涨超1%\", \"language\": null}, \"summary_detail\": {\"base\": \"https://36kr.com/feed\", \"type\": \"text/html\", \"value\": \"36氪获悉，现货白银日内涨超1%，现报79.20美元/盎司。\", \"language\": null}, \"published_parsed\": [2026, 4, 17, 4, 46, 49, 4, 107, 0]}', '2026-04-17 15:08:35');
