INSERT INTO `article_storage` VALUES (39, 2308, '金螳螂：与越南Sun Group签署的备忘录中不涉及任何具体项目及具体金额', '{\"link\": \"https://36kr.com/newsflashes/3770469160043268?f=rss\", \"links\": [{\"rel\": \"alternate\", \"href\": \"https://36kr.com/newsflashes/3770469160043268?f=rss\", \"type\": \"text/html\"}], \"title\": \"金螳螂：与越南Sun Group签署的备忘录中不涉及任何具体项目及具体金额\", \"source\": {\"title\": \"36氪\"}, \"summary\": \"36氪获悉，金螳螂午间公告，近日，公司关注到合作外方越南Sun Group在其所在国家对外发布信息，称与金螳螂签署了23亿美元规模的合作文件，相关报道已被部分国内媒体转载。公司知悉后高度重视，为避免相关信息对广大投资者造成误导，对有关情况进行了核实，现予以澄清说明。公司于2026年4月14日与越南Sun Group签署了《战略合作谅解备忘录》（以下简称“备忘录”）。备忘录系双方经过初步磋商后达成的框架性约定，对双方均不具有法律约束力。双方签署的备忘录中不涉及任何具体项目及具体金额。截至本公告披露日，双方尚未就任何具体合作项目达成具有法律约束力的正式协议。后续合作能否落地实施、具体合作内容及合作规模等，均需双方进一步协商确定，并签署具有法律约束力的正式协议后方可推进。\", \"published\": \"2026-04-17 13:19:34  +0800\", \"title_detail\": {\"base\": \"https://36kr.com/feed\", \"type\": \"text/plain\", \"value\": \"金螳螂：与越南Sun Group签署的备忘录中不涉及任何具体项目及具体金额\", \"language\": null}, \"summary_detail\": {\"base\": \"https://36kr.com/feed\", \"type\": \"text/html\", \"value\": \"36氪获悉，金螳螂午间公告，近日，公司关注到合作外方越南Sun Group在其所在国家对外发布信息，称与金螳螂签署了23亿美元规模的合作文件，相关报道已被部分国内媒体转载。公司知悉后高度重视，为避免相关信息对广大投资者造成误导，对有关情况进行了核实，现予以澄清说明。公司于2026年4月14日与越南Sun Group签署了《战略合作谅解备忘录》（以下简称“备忘录”）。备忘录系双方经过初步磋商后达成的框架性约定，对双方均不具有法律约束力。双方签署的备忘录中不涉及任何具体项目及具体金额。截至本公告披露日，双方尚未就任何具体合作项目达成具有法律约束力的正式协议。后续合作能否落地实施、具体合作内容及合作规模等，均需双方进一步协商确定，并签署具有法律约束力的正式协议后方可推进。\", \"language\": null}, \"published_parsed\": [2026, 4, 17, 5, 19, 34, 4, 107, 0]}', '2026-04-17 15:08:54');
