INSERT INTO `article_storage` VALUES (78, 2361, 'Anthropic 推出 Claude Opus 4.7', '{\"id\": \"https://www.oschina.net/news/430590/claude-opus-4-7\", \"link\": \"https://www.oschina.net/news/430590/claude-opus-4-7\", \"tags\": [{\"term\": \"综合新闻\", \"label\": null, \"scheme\": null}], \"links\": [{\"rel\": \"alternate\", \"href\": \"https://www.oschina.net/news/430590/claude-opus-4-7\", \"type\": \"text/html\"}], \"title\": \"Anthropic 推出 Claude Opus 4.7\", \"summary\": \"Anthropic 宣布其最新款的 Claude Opus 4.7 已全面上市。在高级软件工程方面相比 Opus 4.6 有了显著提升，尤其是在处理最复杂的任务方面。Opus 4.7 能够严谨且一致地处理复杂、耗时的任务，精准地执行指令，并在返回结果之前设计出验证自身输出的方法。 根据介绍，该模型还拥有显著更佳的视觉效果：它能够识别更高分辨率...\", \"published\": \"Fri, 17 Apr 2026 10:21:29 +0800\", \"guidislink\": false, \"title_detail\": {\"base\": \"https://www.oschina.net/news/rss\", \"type\": \"text/plain\", \"value\": \"Anthropic 推出 Claude Opus 4.7\", \"language\": null}, \"summary_detail\": {\"base\": \"https://www.oschina.net/news/rss\", \"type\": \"text/html\", \"value\": \"Anthropic 宣布其最新款的 Claude Opus 4.7 已全面上市。在高级软件工程方面相比 Opus 4.6 有了显著提升，尤其是在处理最复杂的任务方面。Opus 4.7 能够严谨且一致地处理复杂、耗时的任务，精准地执行指令，并在返回结果之前设计出验证自身输出的方法。 根据介绍，该模型还拥有显著更佳的视觉效果：它能够识别更高分辨率...\", \"language\": null}, \"published_parsed\": [2026, 4, 17, 2, 21, 29, 4, 107, 0]}', '2026-04-17 15:09:55');
